export const CHARTS_FORECAST_PLOT_PY = `"""
Forecast Plot — Actual vs Predicted with confidence fan.

Renders historical actuals alongside model predictions with confidence
intervals displayed as a shaded fan chart. Works with output from any
of the forecasting modules (Prophet, ARIMA, Holt-Winters).

Input data:
  [{ "date": "2026-01-15", "actual": 500, "predicted": 480,
     "lower": 420, "upper": 540 }, ...]
"""

import pandas as pd
import numpy as np
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
import matplotlib.dates as mdates
from charts import apply_style, fig_to_base64, get_color_palette, add_watermark, format_currency, currency_formatter


def run(data: list, params: dict, chart_config: dict) -> dict:
    if not data:
        return {"error": "No data provided"}

    colors = apply_style(chart_config)
    palette = get_color_palette(colors, 6)

    df = pd.DataFrame(data)

    # Resolve columns
    date_col = next((c for c in ['date', 'ds', 'period', 'timestamp'] if c in df.columns), None)
    actual_col = next((c for c in ['actual', 'y', 'observed', 'value', 'amount'] if c in df.columns), None)
    pred_col = next((c for c in ['predicted', 'yhat', 'forecast', 'prediction'] if c in df.columns), None)
    lower_col = next((c for c in ['lower', 'yhat_lower', 'lower_bound', 'ci_lower'] if c in df.columns), None)
    upper_col = next((c for c in ['upper', 'yhat_upper', 'upper_bound', 'ci_upper'] if c in df.columns), None)

    if not date_col:
        return {"error": "No date column found"}

    df[date_col] = pd.to_datetime(df[date_col])
    df = df.sort_values(date_col)

    for col in [actual_col, pred_col, lower_col, upper_col]:
        if col:
            df[col] = pd.to_numeric(df[col], errors='coerce')

    # ── Chart ──
    fig, ax = plt.subplots(figsize=(14, 6))

    # Confidence interval fan
    if lower_col and upper_col:
        ci_mask = df[lower_col].notna() & df[upper_col].notna()
        ax.fill_between(
            df.loc[ci_mask, date_col], df.loc[ci_mask, lower_col], df.loc[ci_mask, upper_col],
            alpha=0.15, color=palette[1], label='Confidence Interval'
        )

    # Actual line
    if actual_col:
        actual_mask = df[actual_col].notna()
        ax.plot(df.loc[actual_mask, date_col], df.loc[actual_mask, actual_col],
                color=palette[0], linewidth=2, label='Actual', marker='o', markersize=3)

    # Predicted line
    if pred_col:
        pred_mask = df[pred_col].notna()
        ax.plot(df.loc[pred_mask, date_col], df.loc[pred_mask, pred_col],
                color=palette[1], linewidth=2, linestyle='--', label='Predicted')

    # Forecast boundary line (where actual ends and forecast begins)
    if actual_col and pred_col:
        last_actual_date = df.loc[df[actual_col].notna(), date_col].max()
        ax.axvline(last_actual_date, color='gray', linestyle=':', alpha=0.5, label='Forecast start')

    ax.set_xlabel('Date')
    ax.set_ylabel('Value')
    title = params.get('title', 'Actual vs Forecast')
    ax.set_title(title, fontsize=14, fontweight='bold')
    ax.legend(fontsize=9, loc='best')

    # Format dates
    ax.xaxis.set_major_formatter(mdates.DateFormatter('%b %d'))
    ax.xaxis.set_major_locator(mdates.AutoDateLocator())
    fig.autofmt_xdate()

    # Y-axis currency formatting if configured
    if chart_config.get('currencySymbol'):
        ax.yaxis.set_major_formatter(currency_formatter(chart_config))

    ax.grid(True, alpha=0.2)
    add_watermark(fig, chart_config)
    fig.tight_layout()
    chart = fig_to_base64(fig, chart_config, width=1400, height=600)
    chart['title'] = title

    # ── Compute accuracy metrics ──
    both_mask = pd.Series(True, index=df.index)
    if actual_col:
        both_mask &= df[actual_col].notna()
    if pred_col:
        both_mask &= df[pred_col].notna()

    metrics = {}
    if actual_col and pred_col and both_mask.sum() > 0:
        actual = df.loc[both_mask, actual_col]
        predicted = df.loc[both_mask, pred_col]
        errors = actual - predicted
        abs_errors = errors.abs()

        metrics = {
            'mae': round(float(abs_errors.mean()), 2),
            'rmse': round(float(np.sqrt((errors**2).mean())), 2),
            'mape': round(float((abs_errors / actual.replace(0, np.nan)).dropna().mean() * 100), 2),
            'dataPoints': int(both_mask.sum()),
        }

    # ── Summary ──
    summary = {
        'totalDataPoints': len(df),
        **metrics,
    }

    if actual_col and df[actual_col].notna().sum() > 0:
        summary['actualMean'] = round(float(df[actual_col].dropna().mean()), 2)
        summary['actualTotal'] = round(float(df[actual_col].dropna().sum()), 2)

    if pred_col and df[pred_col].notna().sum() > 0:
        # Future predictions (where actual is NaN)
        future_mask = df[pred_col].notna() & (df[actual_col].isna() if actual_col else True)
        if future_mask.sum() > 0:
            summary['forecastMean'] = round(float(df.loc[future_mask, pred_col].mean()), 2)
            summary['forecastTotal'] = round(float(df.loc[future_mask, pred_col].sum()), 2)
            summary['forecastDays'] = int(future_mask.sum())

    # ── Table ──
    table_cols = ['Date']
    if actual_col:
        table_cols.append('Actual')
    if pred_col:
        table_cols.append('Predicted')
    if lower_col:
        table_cols.append('Lower CI')
    if upper_col:
        table_cols.append('Upper CI')
    if actual_col and pred_col:
        table_cols.append('Error')

    table = {
        'columns': table_cols,
        'rows': [],
    }
    for _, row in df.tail(60).iterrows():
        r = [row[date_col].strftime('%Y-%m-%d')]
        if actual_col:
            r.append(format_currency(row[actual_col], chart_config) if pd.notna(row[actual_col]) else '—')
        if pred_col:
            r.append(format_currency(row[pred_col], chart_config) if pd.notna(row[pred_col]) else '—')
        if lower_col:
            r.append(format_currency(row[lower_col], chart_config) if pd.notna(row[lower_col]) else '—')
        if upper_col:
            r.append(format_currency(row[upper_col], chart_config) if pd.notna(row[upper_col]) else '—')
        if actual_col and pred_col:
            if pd.notna(row[actual_col]) and pd.notna(row[pred_col]):
                err = row[actual_col] - row[pred_col]
                r.append(format_currency(err, chart_config))
            else:
                r.append('—')
        table['rows'].append(r)

    return {
        'summary': summary,
        'charts': [chart],
        'table': table,
    }
`;

export const CHARTS_GEO_MAP_PY = `"""
Geographic Map — Regional performance visualization.

Renders a bar/choropleth-style chart showing revenue, quantity, or other metrics
by region/county/area. Designed to work with any geographic hierarchy.

Input data:
  [{ "region": "Nairobi", "revenue": 500000, "quantity": 1200, "orders": 300 }, ...]
"""

import pandas as pd
import numpy as np
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
from charts import apply_style, fig_to_base64, get_color_palette, add_watermark, format_currency, currency_formatter


def run(data: list, params: dict, chart_config: dict) -> dict:
    if not data:
        return {"error": "No data provided"}

    colors = apply_style(chart_config)
    palette = get_color_palette(colors, 20)

    df = pd.DataFrame(data)

    # Resolve columns
    region_col = next((c for c in ['region', 'county', 'area', 'city', 'location', 'zone', 'state', 'province'] if c in df.columns), None)
    value_col = next((c for c in ['revenue', 'amount', 'total', 'sales', 'quantity', 'orders'] if c in df.columns), None)
    qty_col = next((c for c in ['quantity', 'qty', 'units', 'orders', 'count'] if c in df.columns), None)

    if not region_col:
        return {"error": "No region/location column found"}
    if not value_col:
        return {"error": "No value column found"}

    df[value_col] = pd.to_numeric(df[value_col], errors='coerce').fillna(0)
    if qty_col and qty_col != value_col:
        df[qty_col] = pd.to_numeric(df[qty_col], errors='coerce').fillna(0)

    # Aggregate by region
    agg_dict = {value_col: 'sum'}
    if qty_col and qty_col != value_col:
        agg_dict[qty_col] = 'sum'
    grouped = df.groupby(region_col).agg(agg_dict).reset_index()
    grouped = grouped.sort_values(value_col, ascending=False)

    total_value = grouped[value_col].sum()

    # ── Charts ──
    fig, axes = plt.subplots(1, 2, figsize=(16, max(6, len(grouped) * 0.35)))

    # 1. Horizontal bar chart (all regions)
    y_pos = range(len(grouped))
    bars = axes[0].barh(y_pos, grouped[value_col], color=palette[:len(grouped)], alpha=0.85)
    axes[0].set_yticks(y_pos)
    axes[0].set_yticklabels(grouped[region_col], fontsize=9)
    axes[0].set_xlabel('Revenue')
    axes[0].set_title('Revenue by Region', fontsize=13, fontweight='bold')
    axes[0].invert_yaxis()
    axes[0].xaxis.set_major_formatter(currency_formatter(chart_config))

    # Percentage labels on bars
    for i, (_, row) in enumerate(grouped.iterrows()):
        pct = row[value_col] / total_value * 100 if total_value > 0 else 0
        axes[0].text(row[value_col] * 1.02, i,
                    f"{format_currency(row[value_col], chart_config)} ({pct:.1f}%)",
                    va='center', fontsize=8)

    # 2. Top regions as pie / donut
    top_n = min(8, len(grouped))
    top = grouped.head(top_n).copy()
    if len(grouped) > top_n:
        others_val = grouped.iloc[top_n:][value_col].sum()
        others_row = pd.DataFrame({region_col: ['Others'], value_col: [others_val]})
        top = pd.concat([top, others_row], ignore_index=True)

    wedges, texts, autotexts = axes[1].pie(
        top[value_col], labels=top[region_col],
        autopct='%1.1f%%', colors=palette[:len(top)],
        startangle=90, textprops={'fontsize': 9},
        pctdistance=0.75
    )
    # Donut center
    centre_circle = plt.Circle((0, 0), 0.45, fc='white')
    axes[1].add_artist(centre_circle)
    axes[1].text(0, 0, f"Total\\n{format_currency(total_value, chart_config)}",
                ha='center', va='center', fontsize=10, fontweight='bold')
    axes[1].set_title('Regional Share', fontsize=13, fontweight='bold')

    add_watermark(fig, chart_config)
    fig.tight_layout()
    chart = fig_to_base64(fig, chart_config, width=1600, height=max(600, len(grouped) * 35))
    chart['title'] = 'Geographic Performance'

    # ── Summary ──
    summary = {
        'totalRevenue': round(float(total_value), 2),
        'regionCount': len(grouped),
        'topRegion': str(grouped.iloc[0][region_col]),
        'topRegionRevenue': round(float(grouped.iloc[0][value_col]), 2),
        'topRegionPct': round(float(grouped.iloc[0][value_col] / total_value * 100), 1) if total_value > 0 else 0,
        'top3Pct': round(float(grouped.head(3)[value_col].sum() / total_value * 100), 1) if total_value > 0 else 0,
        'bottomRegion': str(grouped.iloc[-1][region_col]),
        'bottomRegionRevenue': round(float(grouped.iloc[-1][value_col]), 2),
    }

    # ── Table ──
    table_cols = ['Rank', 'Region', 'Revenue', '% Share', 'Cumulative %']
    if qty_col and qty_col != value_col:
        table_cols.insert(3, 'Quantity')

    table = {'columns': table_cols, 'rows': []}
    cumulative = 0
    for rank, (_, row) in enumerate(grouped.iterrows(), 1):
        pct = row[value_col] / total_value * 100 if total_value > 0 else 0
        cumulative += pct
        r = [rank, str(row[region_col]), format_currency(row[value_col], chart_config)]
        if qty_col and qty_col != value_col:
            r.append(int(row[qty_col]))
        r.extend([f"{pct:.1f}%", f"{cumulative:.1f}%"])
        table['rows'].append(r)

    return {
        'summary': summary,
        'charts': [chart],
        'table': table,
    }
`;

export const CHARTS_HEATMAP_PY = `"""
Revenue Heatmap — Branch × Time Period intensity heatmap.

Input data format:
  [{ "branch_name": "Main", "date": "2026-01-15", "total_amount": 15000 }, ...]

Shows sales intensity by branch and day-of-week/month to spot patterns.
"""

import pandas as pd
import numpy as np
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
import seaborn as sns
from charts import apply_style, fig_to_base64, currency_formatter, add_watermark, format_currency


def run(data: list, params: dict, chart_config: dict) -> dict:
    if not data:
        return {"error": "No data provided for heatmap"}

    colors = apply_style(chart_config)

    df = pd.DataFrame(data)

    # Normalize columns
    date_col = next((c for c in ['date', 'sale_date', 'created_at', 'order_date'] if c in df.columns), None)
    amount_col = next((c for c in ['total_amount', 'amount', 'revenue', 'total'] if c in df.columns), None)
    group_col = next((c for c in ['branch_name', 'warehouse_name', 'location', 'category_name'] if c in df.columns), None)

    if not date_col or not amount_col:
        return {"error": "Missing required columns: need a date column and an amount column"}

    df[date_col] = pd.to_datetime(df[date_col])
    df[amount_col] = pd.to_numeric(df[amount_col], errors='coerce').fillna(0)

    # Determine heatmap mode
    mode = params.get('heatmapMode', 'day_of_week')
    
    charts = []

    if group_col and df[group_col].nunique() > 1:
        # Branch × Time heatmap
        if mode == 'month':
            df['period'] = df[date_col].dt.strftime('%Y-%m')
            period_label = 'Month'
        elif mode == 'week':
            df['period'] = df[date_col].dt.isocalendar().week.astype(str)
            period_label = 'Week'
        else:
            df['period'] = df[date_col].dt.day_name()
            period_label = 'Day of Week'
            day_order = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday']
            df['period'] = pd.Categorical(df['period'], categories=day_order, ordered=True)

        pivot = df.pivot_table(
            values=amount_col,
            index=group_col,
            columns='period',
            aggfunc='sum',
            fill_value=0
        )

        fig, ax = plt.subplots(figsize=(12, max(4, len(pivot) * 0.6 + 2)))
        
        sns.heatmap(
            pivot,
            annot=True,
            fmt=',.0f',
            cmap='YlOrRd',
            linewidths=0.5,
            linecolor='white',
            ax=ax,
            cbar_kws={'label': 'Revenue', 'format': currency_formatter(chart_config)}
        )
        
        ax.set_title(f'Revenue Heatmap — {group_col.replace("_", " ").title()} × {period_label}',
                     fontsize=14, fontweight='bold', pad=15)
        ax.set_ylabel('')
        ax.set_xlabel(period_label)
        
    else:
        # Day-of-week × Hour heatmap (single location)
        if 'hour' not in df.columns:
            df['hour'] = df[date_col].dt.hour
        df['day'] = df[date_col].dt.day_name()
        day_order = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday']
        df['day'] = pd.Categorical(df['day'], categories=day_order, ordered=True)
        
        pivot = df.pivot_table(
            values=amount_col,
            index='day',
            columns='hour',
            aggfunc='sum',
            fill_value=0
        )

        fig, ax = plt.subplots(figsize=(14, 5))
        
        sns.heatmap(
            pivot,
            annot=True,
            fmt=',.0f',
            cmap='YlOrRd',
            linewidths=0.5,
            linecolor='white',
            ax=ax,
            cbar_kws={'label': 'Revenue'}
        )
        
        ax.set_title('Revenue Heatmap — Day × Hour',
                     fontsize=14, fontweight='bold', pad=15)
        ax.set_ylabel('')
        ax.set_xlabel('Hour of Day')

    add_watermark(fig, chart_config)
    fig.tight_layout()

    chart = fig_to_base64(fig, chart_config, width=1200, height=600)
    chart['title'] = 'Revenue Heatmap'
    charts.append(chart)

    # Summary
    if group_col and group_col in df.columns:
        branch_totals = df.groupby(group_col)[amount_col].sum().sort_values(ascending=False)
        top_branch = branch_totals.index[0] if len(branch_totals) > 0 else 'N/A'
        summary = {
            'topBranch': top_branch,
            'topBranchRevenue': float(branch_totals.iloc[0]) if len(branch_totals) > 0 else 0,
            'branchCount': int(df[group_col].nunique()),
            'totalRevenue': float(df[amount_col].sum()),
            'totalRevenueFormatted': format_currency(df[amount_col].sum(), chart_config),
        }
    else:
        summary = {
            'totalRevenue': float(df[amount_col].sum()),
            'totalRevenueFormatted': format_currency(df[amount_col].sum(), chart_config),
        }

    return {
        'summary': summary,
        'charts': charts,
    }
`;

export const CHARTS_PARETO_PY = `"""
Pareto Chart (80/20) — ABC inventory analysis.

Combined bar chart + cumulative percentage line showing which products
drive the majority of revenue. The classic 80/20 rule visualization.

Input data format:
  [{ "name": "Safari Hat", "total_revenue": 150000, "total_quantity": 200 }, ...]
"""

import pandas as pd
import numpy as np
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
from charts import apply_style, fig_to_base64, currency_formatter, get_color_palette, add_watermark, format_currency


def run(data: list, params: dict, chart_config: dict) -> dict:
    if not data:
        return {"error": "No data provided for Pareto chart"}

    colors = apply_style(chart_config)
    palette = get_color_palette(colors, 3)

    df = pd.DataFrame(data)

    # Normalize columns
    name_col = next((c for c in ['name', 'product_name', 'sku', 'item'] if c in df.columns), None)
    value_col = next((c for c in ['total_revenue', 'revenue', 'total_amount', 'amount', 'value'] if c in df.columns), None)

    if not name_col or not value_col:
        return {"error": "Missing required columns: need a name column and a revenue/value column"}

    df[value_col] = pd.to_numeric(df[value_col], errors='coerce').fillna(0)
    df = df.sort_values(value_col, ascending=False).reset_index(drop=True)

    # Limit to top N items for readability
    max_items = params.get('maxItems', 20)
    if len(df) > max_items:
        other_total = df.iloc[max_items:][value_col].sum()
        df = df.head(max_items).copy()
        other_row = pd.DataFrame([{name_col: f'Other ({len(data) - max_items} items)', value_col: other_total}])
        df = pd.concat([df, other_row], ignore_index=True)

    # Calculate cumulative percentage
    total = df[value_col].sum()
    df['cumulative_pct'] = (df[value_col].cumsum() / total * 100) if total > 0 else 0

    # ABC classification thresholds
    a_threshold = params.get('aThresholdPct', params.get('abc', {}).get('aThresholdPct', 80))
    b_threshold = a_threshold + params.get('bThresholdPct', params.get('abc', {}).get('bThresholdPct', 15))

    # Color bars by ABC class
    bar_colors = []
    for pct in df['cumulative_pct']:
        if pct <= a_threshold:
            bar_colors.append(palette[0])  # A items — primary
        elif pct <= b_threshold:
            bar_colors.append(palette[1])  # B items — secondary
        else:
            bar_colors.append('#9ca3af')   # C items — gray

    # Create figure with dual y-axis
    fig, ax1 = plt.subplots(figsize=(12, 6))
    ax2 = ax1.twinx()

    # Bar chart (revenue)
    x = range(len(df))
    ax1.bar(x, df[value_col], color=bar_colors, alpha=0.85, edgecolor='white', linewidth=0.5)

    # Cumulative line
    ax2.plot(x, df['cumulative_pct'], color=palette[2], linewidth=2.5,
             marker='o', markersize=4, zorder=5)

    # 80% threshold line
    ax2.axhline(y=a_threshold, color='red', linestyle='--', alpha=0.5, linewidth=1)
    ax2.text(len(df) - 1, a_threshold + 1.5, f'{a_threshold}%', color='red',
             fontsize=9, ha='right', alpha=0.7)

    # Labels
    ax1.set_title('Pareto Analysis — Product Revenue Contribution',
                  fontsize=14, fontweight='bold', pad=15)
    ax1.set_xlabel('')
    ax1.set_ylabel('Revenue', fontsize=11)
    ax2.set_ylabel('Cumulative %', fontsize=11)

    # X-axis labels (rotated)
    labels = df[name_col].tolist()
    # Truncate long names
    labels = [l[:20] + '...' if len(str(l)) > 20 else str(l) for l in labels]
    ax1.set_xticks(list(x))
    ax1.set_xticklabels(labels, rotation=45, ha='right', fontsize=8)

    # Format y-axes
    ax1.yaxis.set_major_formatter(currency_formatter(chart_config))
    ax2.set_ylim(0, 105)
    ax2.yaxis.set_major_formatter(plt.FuncFormatter(lambda y, _: f'{y:.0f}%'))

    # Legend
    from matplotlib.patches import Patch
    legend_elements = [
        Patch(facecolor=palette[0], label=f'A Items (top {a_threshold}% rev)'),
        Patch(facecolor=palette[1], label=f'B Items (next {b_threshold - a_threshold}%)'),
        Patch(facecolor='#9ca3af', label=f'C Items (remaining {100 - b_threshold}%)'),
    ]
    ax1.legend(handles=legend_elements, loc='center left', fontsize=9, framealpha=0.9)

    ax1.grid(True, alpha=0.2, axis='y')

    add_watermark(fig, chart_config)
    fig.tight_layout()

    chart = fig_to_base64(fig, chart_config, width=1200, height=600)
    chart['title'] = 'Pareto Analysis'

    # Summary — ABC classification counts
    a_count = sum(1 for pct in df['cumulative_pct'] if pct <= a_threshold)
    b_count = sum(1 for pct in df['cumulative_pct'] if a_threshold < pct <= b_threshold)
    c_count = len(df) - a_count - b_count

    a_revenue = float(df.head(a_count)[value_col].sum()) if a_count > 0 else 0
    b_revenue = float(df.iloc[a_count:a_count + b_count][value_col].sum()) if b_count > 0 else 0
    c_revenue = float(df.iloc[a_count + b_count:][value_col].sum())

    summary = {
        'totalProducts': len(data),
        'totalRevenue': float(total),
        'totalRevenueFormatted': format_currency(total, chart_config),
        'aItems': {
            'count': a_count,
            'revenue': a_revenue,
            'revenueFormatted': format_currency(a_revenue, chart_config),
            'pct': round(a_revenue / total * 100, 1) if total > 0 else 0,
        },
        'bItems': {
            'count': b_count,
            'revenue': b_revenue,
            'revenueFormatted': format_currency(b_revenue, chart_config),
            'pct': round(b_revenue / total * 100, 1) if total > 0 else 0,
        },
        'cItems': {
            'count': c_count,
            'revenue': c_revenue,
            'revenueFormatted': format_currency(c_revenue, chart_config),
            'pct': round(c_revenue / total * 100, 1) if total > 0 else 0,
        },
        'topProduct': str(df.iloc[0][name_col]) if len(df) > 0 else 'N/A',
        'topProductRevenue': float(df.iloc[0][value_col]) if len(df) > 0 else 0,
    }

    return {
        'summary': summary,
        'charts': [chart],
    }
`;

export const CHARTS_RENDER_CHART_PY = `"""
Generic Chart Renderer — Renders ChartSpec JSON to enterprise matplotlib charts.

This module is the Python-first replacement for the Vega-Lite rendering pipeline.
It accepts the SAME ChartSpec format that the LLM generates in \`\`\`chart blocks,
and renders enterprise-grade matplotlib charts with brand styling, currency
formatting, gradient fills, and watermarks.

Input (via params.charts):
  [
    {
      "type": "line",
      "title": "Daily Revenue Trend",
      "data": [{"date": "2026-01-01", "revenue": 15000}, ...],
      "xField": "date",
      "yField": "revenue",
      "xLabel": "Date",
      "yLabel": "Revenue",
      "colorField": "category",
      "width": 1000,
      "height": 500
    },
    ...
  ]

Output:
  {
    "summary": { "chartsRendered": N },
    "charts": [{ "title": ..., "format": "png", "data": "base64...", "width": W, "height": H }]
  }

Supported chart types:
  line, bar, grouped_bar, stacked_bar, area, pie, donut, scatter, heatmap
"""

import pandas as pd
import numpy as np
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
import matplotlib.dates as mdates
import matplotlib.ticker as mticker
from charts import apply_style, fig_to_base64, currency_formatter, get_color_palette, add_watermark, format_currency

# ── Helpers ──────────────────────────────────────────────────

def _is_date_field(values) -> bool:
    """Check if a series looks like dates."""
    if len(values) == 0:
        return False
    sample = str(values.iloc[0]) if hasattr(values, 'iloc') else str(values[0])
    import re
    return bool(re.match(r'^\\d{4}-\\d{2}(-\\d{2})?', sample))


def _is_currency_field(field_name: str) -> bool:
    """Heuristic: does this field name suggest monetary values?"""
    currency_hints = [
        'revenue', 'amount', 'total', 'price', 'cost', 'profit', 'sales',
        'income', 'expense', 'margin', 'value', 'payment', 'fee', 'spend',
        'budget', 'net', 'gross',
    ]
    name_lower = (field_name or '').lower().replace('_', ' ')
    return any(hint in name_lower for hint in currency_hints)


def _smart_number_format(field_name: str, chart_config: dict):
    """Return a formatter: currency if the field looks monetary, else compact."""
    if _is_currency_field(field_name):
        return currency_formatter(chart_config)
    else:
        def _fmt(x, pos):
            if abs(x) >= 1_000_000:
                return f'{x/1_000_000:,.1f}M'
            elif abs(x) >= 1_000:
                return f'{x/1_000:,.1f}K'
            else:
                return f'{x:,.0f}'
        return mticker.FuncFormatter(_fmt)


# ── Chart Type Renderers ─────────────────────────────────────

def _render_line(spec: dict, chart_config: dict, colors: dict, palette: list) -> plt.Figure:
    """Render a line chart with optional moving average and confidence band."""
    df = pd.DataFrame(spec['data'])
    x_field = spec.get('xField', 'x')
    y_field = spec.get('yField', 'y')
    color_field = spec.get('colorField')
    title = spec.get('title', 'Line Chart')

    fig, ax = plt.subplots(figsize=(10, 5))

    if _is_date_field(df[x_field]):
        df[x_field] = pd.to_datetime(df[x_field])
        df = df.sort_values(x_field)

    if color_field and color_field in df.columns:
        # Multi-series
        groups = df[color_field].unique()
        for i, group in enumerate(groups):
            subset = df[df[color_field] == group]
            c = palette[i % len(palette)]
            ax.plot(subset[x_field], pd.to_numeric(subset[y_field], errors='coerce'),
                    color=c, linewidth=2.5, label=str(group),
                    marker='o', markersize=4)
    else:
        # Single series with MA + confidence band
        y_vals = pd.to_numeric(df[y_field], errors='coerce').fillna(0)
        ax.plot(df[x_field], y_vals, color=palette[0], alpha=0.4,
                linewidth=1, label=y_field.replace('_', ' ').title())

        if len(y_vals) >= 5:
            ma_window = min(7, max(3, len(y_vals) // 5))
            ma = y_vals.rolling(window=ma_window, min_periods=1).mean()
            ax.plot(df[x_field], ma, color=palette[0], linewidth=2.5,
                    label=f'{ma_window}-pt Moving Average')
            ax.fill_between(df[x_field].values, ma * 0.85, ma * 1.15,
                            color=palette[0], alpha=0.08)

    ax.set_title(title, fontsize=14, fontweight='bold', pad=15)
    ax.set_xlabel(spec.get('xLabel', ''), fontsize=11)
    ax.set_ylabel(spec.get('yLabel', y_field.replace('_', ' ').title()), fontsize=11)

    if _is_date_field(df[x_field]):
        ax.xaxis.set_major_formatter(mdates.DateFormatter('%b %d'))
        ax.xaxis.set_major_locator(mdates.AutoDateLocator())
        fig.autofmt_xdate()

    ax.yaxis.set_major_formatter(_smart_number_format(y_field, chart_config))
    ax.legend(loc='upper left', framealpha=0.9, fontsize=9)
    ax.grid(True, alpha=0.3)

    return fig


def _render_bar(spec: dict, chart_config: dict, colors: dict, palette: list) -> plt.Figure:
    """Render a bar chart with rounded appearance."""
    df = pd.DataFrame(spec['data'])
    x_field = spec.get('xField', 'x')
    y_field = spec.get('yField', 'y')
    color_field = spec.get('colorField')
    title = spec.get('title', 'Bar Chart')
    chart_type = spec.get('type', 'bar').lower().replace('_', '')

    df[y_field] = pd.to_numeric(df[y_field], errors='coerce').fillna(0)
    fig, ax = plt.subplots(figsize=(10, 5))

    if color_field and color_field in df.columns and chart_type in ('groupedbar', 'stackedbar'):
        groups = df[color_field].unique()
        x_labels = df[x_field].unique()
        x_pos = np.arange(len(x_labels))
        bar_width = 0.8 / max(len(groups), 1)

        if chart_type == 'stackedbar':
            bottom = np.zeros(len(x_labels))
            for i, group in enumerate(groups):
                vals = []
                for label in x_labels:
                    match = df[(df[x_field] == label) & (df[color_field] == group)]
                    vals.append(match[y_field].sum() if len(match) > 0 else 0)
                c = palette[i % len(palette)]
                ax.bar(x_pos, vals, bottom=bottom, color=c, label=str(group),
                       edgecolor='white', linewidth=0.5)
                bottom += np.array(vals)
        else:
            # Grouped
            for i, group in enumerate(groups):
                vals = []
                for label in x_labels:
                    match = df[(df[x_field] == label) & (df[color_field] == group)]
                    vals.append(match[y_field].sum() if len(match) > 0 else 0)
                c = palette[i % len(palette)]
                offset = (i - len(groups)/2 + 0.5) * bar_width
                ax.bar(x_pos + offset, vals, bar_width, color=c, label=str(group),
                       edgecolor='white', linewidth=0.5)

        ax.set_xticks(x_pos)
        ax.set_xticklabels([str(l) for l in x_labels], rotation=30, ha='right')
        ax.legend(loc='upper right', framealpha=0.9, fontsize=9)
    else:
        # Simple bar chart — gradient-like effect via varying alpha
        y_vals = df[y_field].values
        x_labels = [str(v) for v in df[x_field].values]
        x_pos = np.arange(len(x_labels))

        # Color bars by value intensity
        max_val = max(abs(y_vals.max()), abs(y_vals.min()), 1)
        alphas = 0.5 + 0.5 * (np.abs(y_vals) / max_val)

        for i, (pos, val, alpha) in enumerate(zip(x_pos, y_vals, alphas)):
            ax.bar(pos, val, color=palette[0], alpha=alpha,
                   edgecolor='white', linewidth=0.5)

        ax.set_xticks(x_pos)
        ax.set_xticklabels(x_labels, rotation=30, ha='right', fontsize=9)

    ax.set_title(title, fontsize=14, fontweight='bold', pad=15)
    ax.set_xlabel(spec.get('xLabel', ''), fontsize=11)
    ax.set_ylabel(spec.get('yLabel', y_field.replace('_', ' ').title()), fontsize=11)
    ax.yaxis.set_major_formatter(_smart_number_format(y_field, chart_config))
    ax.grid(True, alpha=0.2, axis='y')

    return fig


def _render_area(spec: dict, chart_config: dict, colors: dict, palette: list) -> plt.Figure:
    """Render an area chart with gradient fill."""
    df = pd.DataFrame(spec['data'])
    x_field = spec.get('xField', 'x')
    y_field = spec.get('yField', 'y')
    color_field = spec.get('colorField')
    title = spec.get('title', 'Area Chart')

    df[y_field] = pd.to_numeric(df[y_field], errors='coerce').fillna(0)
    fig, ax = plt.subplots(figsize=(10, 5))

    if _is_date_field(df[x_field]):
        df[x_field] = pd.to_datetime(df[x_field])
        df = df.sort_values(x_field)

    if color_field and color_field in df.columns:
        groups = df[color_field].unique()
        for i, group in enumerate(groups):
            subset = df[df[color_field] == group].sort_values(x_field)
            c = palette[i % len(palette)]
            vals = subset[y_field].values
            ax.fill_between(subset[x_field].values, 0, vals, color=c, alpha=0.3, label=str(group))
            ax.plot(subset[x_field], vals, color=c, linewidth=2)
        ax.legend(loc='upper left', framealpha=0.9, fontsize=9)
    else:
        y_vals = df[y_field].values
        ax.fill_between(df[x_field].values, 0, y_vals, color=palette[0], alpha=0.3)
        ax.plot(df[x_field], y_vals, color=palette[0], linewidth=2)

    ax.set_title(title, fontsize=14, fontweight='bold', pad=15)
    ax.set_xlabel(spec.get('xLabel', ''), fontsize=11)
    ax.set_ylabel(spec.get('yLabel', y_field.replace('_', ' ').title()), fontsize=11)
    ax.yaxis.set_major_formatter(_smart_number_format(y_field, chart_config))

    if _is_date_field(df[x_field]):
        ax.xaxis.set_major_formatter(mdates.DateFormatter('%b %d'))
        fig.autofmt_xdate()

    ax.grid(True, alpha=0.3)
    return fig


def _render_pie(spec: dict, chart_config: dict, colors: dict, palette: list, donut: bool = False) -> plt.Figure:
    """Render a pie or donut chart."""
    df = pd.DataFrame(spec['data'])
    label_field = spec.get('colorField') or spec.get('xField', 'label')
    value_field = spec.get('yField', 'value')
    title = spec.get('title', 'Pie Chart')

    df[value_field] = pd.to_numeric(df[value_field], errors='coerce').fillna(0)
    df = df[df[value_field] > 0]

    # Limit slices — group small ones into "Other"
    if len(df) > 8:
        df = df.sort_values(value_field, ascending=False)
        top = df.head(7)
        other_val = df.iloc[7:][value_field].sum()
        other_row = pd.DataFrame([{label_field: 'Other', value_field: other_val}])
        df = pd.concat([top, other_row], ignore_index=True)

    fig, ax = plt.subplots(figsize=(8, 6))

    wedge_colors = palette[:len(df)]
    wedges, texts, autotexts = ax.pie(
        df[value_field],
        labels=df[label_field],
        colors=wedge_colors,
        autopct='%1.1f%%',
        startangle=90,
        pctdistance=0.75 if donut else 0.6,
        wedgeprops=dict(width=0.5 if donut else 1, edgecolor='white', linewidth=2),
    )

    for text in texts:
        text.set_fontsize(9)
    for autotext in autotexts:
        autotext.set_fontsize(8)
        autotext.set_fontweight('bold')

    ax.set_title(title, fontsize=14, fontweight='bold', pad=20)
    return fig


def _render_scatter(spec: dict, chart_config: dict, colors: dict, palette: list) -> plt.Figure:
    """Render a scatter plot with optional trend line."""
    df = pd.DataFrame(spec['data'])
    x_field = spec.get('xField', 'x')
    y_field = spec.get('yField', 'y')
    color_field = spec.get('colorField')
    title = spec.get('title', 'Scatter Plot')

    df[x_field] = pd.to_numeric(df[x_field], errors='coerce')
    df[y_field] = pd.to_numeric(df[y_field], errors='coerce')
    df = df.dropna(subset=[x_field, y_field])

    fig, ax = plt.subplots(figsize=(10, 6))

    if color_field and color_field in df.columns:
        groups = df[color_field].unique()
        for i, group in enumerate(groups):
            subset = df[df[color_field] == group]
            c = palette[i % len(palette)]
            ax.scatter(subset[x_field], subset[y_field], color=c, s=50,
                       alpha=0.7, label=str(group), edgecolors='white', linewidth=0.5)
        ax.legend(loc='best', framealpha=0.9, fontsize=9)
    else:
        ax.scatter(df[x_field], df[y_field], color=palette[0], s=50,
                   alpha=0.7, edgecolors='white', linewidth=0.5)

    # Add trend line if enough points
    if len(df) >= 3:
        try:
            z = np.polyfit(df[x_field].values, df[y_field].values, 1)
            p = np.poly1d(z)
            x_sorted = np.sort(df[x_field].values)
            ax.plot(x_sorted, p(x_sorted), '--', color=colors['accent'],
                    linewidth=1.5, alpha=0.6, label='Trend')
        except Exception:
            pass

    ax.set_title(title, fontsize=14, fontweight='bold', pad=15)
    ax.set_xlabel(spec.get('xLabel', x_field.replace('_', ' ').title()), fontsize=11)
    ax.set_ylabel(spec.get('yLabel', y_field.replace('_', ' ').title()), fontsize=11)
    ax.xaxis.set_major_formatter(_smart_number_format(x_field, chart_config))
    ax.yaxis.set_major_formatter(_smart_number_format(y_field, chart_config))
    ax.grid(True, alpha=0.3)
    return fig


def _render_heatmap(spec: dict, chart_config: dict, colors: dict, palette: list) -> plt.Figure:
    """Render a heatmap chart."""
    import seaborn as sns

    df = pd.DataFrame(spec['data'])
    x_field = spec.get('xField', 'x')
    y_field = spec.get('yField', 'y')
    value_field = spec.get('colorField', 'value')
    title = spec.get('title', 'Heatmap')

    # Pivot data into matrix form
    df[value_field] = pd.to_numeric(df[value_field], errors='coerce').fillna(0)
    try:
        pivot = df.pivot_table(index=y_field, columns=x_field, values=value_field,
                               aggfunc='sum', fill_value=0)
    except Exception:
        pivot = pd.DataFrame(df.set_index([y_field, x_field])[value_field]).unstack(fill_value=0)

    fig, ax = plt.subplots(figsize=(10, max(6, len(pivot) * 0.5 + 2)))
    sns.heatmap(pivot, annot=True, fmt='.0f', cmap='Blues', linewidths=0.5,
                ax=ax, cbar_kws={'shrink': 0.8})

    ax.set_title(title, fontsize=14, fontweight='bold', pad=15)
    ax.set_xlabel(spec.get('xLabel', x_field.replace('_', ' ').title()), fontsize=11)
    ax.set_ylabel(spec.get('yLabel', y_field.replace('_', ' ').title()), fontsize=11)
    plt.yticks(rotation=0)
    return fig


# ── Main Dispatcher ──────────────────────────────────────────

RENDERERS = {
    'line': _render_line,
    'bar': _render_bar,
    'grouped_bar': _render_bar,
    'groupedbar': _render_bar,
    'stacked_bar': _render_bar,
    'stackedbar': _render_bar,
    'area': _render_area,
    'pie': lambda s, cc, co, p: _render_pie(s, cc, co, p, donut=False),
    'donut': lambda s, cc, co, p: _render_pie(s, cc, co, p, donut=True),
    'arc': lambda s, cc, co, p: _render_pie(s, cc, co, p, donut=False),
    'scatter': _render_scatter,
    'point': _render_scatter,
    'heatmap': _render_heatmap,
    'rect': _render_heatmap,
}


def run(data: list, params: dict, chart_config: dict) -> dict:
    """
    Render one or more ChartSpec objects to enterprise matplotlib charts.

    Unlike other analytics modules, the actual chart data is inside
    params['charts'] (array of ChartSpec objects), not in the 'data' arg.
    The 'data' arg is ignored (kept for interface compatibility).
    """
    chart_specs = params.get('charts', [])
    if not chart_specs:
        return {"error": "No chart specifications provided in params.charts"}

    colors = apply_style(chart_config)
    palette = get_color_palette(colors, 10)

    rendered_charts = []
    errors = []

    for i, spec in enumerate(chart_specs):
        chart_type = (spec.get('type', 'bar') or 'bar').lower().replace('-', '').replace('_', '')

        renderer = RENDERERS.get(chart_type)
        if not renderer:
            # Fallback: try bar chart for unknown types
            renderer = _render_bar

        try:
            fig = renderer(spec, chart_config, colors, palette)
            add_watermark(fig, chart_config)
            fig.tight_layout()

            w = spec.get('width', 1000)
            h = spec.get('height', 500)
            chart_out = fig_to_base64(fig, chart_config, width=w, height=h)
            chart_out['title'] = spec.get('title', f'Chart {i + 1}')
            rendered_charts.append(chart_out)
        except Exception as e:
            errors.append(f"Chart {i + 1} ({spec.get('title', 'untitled')}): {str(e)}")
            # Close figure on error to prevent memory leaks
            plt.close('all')

    result = {
        'summary': {
            'chartsRendered': len(rendered_charts),
            'chartsFailed': len(errors),
            'totalRequested': len(chart_specs),
        },
        'charts': rendered_charts,
    }

    if errors:
        result['summary']['errors'] = errors

    return result
`;

export const CHARTS_SALES_TRENDS_PY = `"""
Sales Trends Chart — Time series line chart with moving averages.

Input data format:
  [{ "date": "2026-01-15", "total_amount": 15000, "branch_name": "Main" }, ...]

Output:
  { "summary": { ... }, "charts": [{ "title": ..., "format": "png", "data": "base64...", ... }] }
"""

import pandas as pd
import numpy as np
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
import matplotlib.dates as mdates
from charts import apply_style, fig_to_base64, currency_formatter, get_color_palette, add_watermark, format_currency


def run(data: list, params: dict, chart_config: dict) -> dict:
    if not data:
        return {"error": "No data provided for sales trends chart"}

    colors = apply_style(chart_config)
    palette = get_color_palette(colors, 8)

    df = pd.DataFrame(data)
    
    # Normalize date column
    date_col = None
    for col in ['date', 'sale_date', 'created_at', 'order_date']:
        if col in df.columns:
            date_col = col
            break
    if not date_col:
        return {"error": "No date column found. Expected: date, sale_date, created_at, or order_date"}

    # Normalize amount column
    amount_col = None
    for col in ['total_amount', 'amount', 'revenue', 'total', 'net_amount']:
        if col in df.columns:
            amount_col = col
            break
    if not amount_col:
        return {"error": "No amount column found. Expected: total_amount, amount, revenue, or total"}

    df[date_col] = pd.to_datetime(df[date_col])
    df[amount_col] = pd.to_numeric(df[amount_col], errors='coerce').fillna(0)

    # Aggregate by date
    daily = df.groupby(df[date_col].dt.date).agg(
        total=(amount_col, 'sum'),
        count=(amount_col, 'count')
    ).reset_index()
    daily.columns = ['date', 'total', 'count']
    daily['date'] = pd.to_datetime(daily['date'])
    daily = daily.sort_values('date')

    # Moving averages
    ma_window = params.get('movingAverageWindow', 7)
    daily['ma'] = daily['total'].rolling(window=ma_window, min_periods=1).mean()

    # Create figure
    fig, ax = plt.subplots(figsize=(10, 5))

    # Revenue line
    ax.plot(daily['date'], daily['total'], color=palette[0], alpha=0.4,
            linewidth=1, label='Daily Revenue')
    
    # Moving average line
    ax.plot(daily['date'], daily['ma'], color=palette[0], linewidth=2.5,
            label=f'{ma_window}-Day Moving Average')

    # Fill between for confidence band
    lower = daily['ma'] * 0.85
    upper = daily['ma'] * 1.15
    ax.fill_between(daily['date'], lower, upper, color=palette[0], alpha=0.08)

    # Formatting
    ax.set_title('Sales Trend', fontsize=14, fontweight='bold', pad=15)
    ax.set_xlabel('')
    ax.set_ylabel('Revenue', fontsize=11)
    ax.yaxis.set_major_formatter(currency_formatter(chart_config))
    ax.xaxis.set_major_formatter(mdates.DateFormatter('%b %d'))
    ax.xaxis.set_major_locator(mdates.AutoDateLocator())
    ax.legend(loc='upper left', framealpha=0.9)
    ax.grid(True, alpha=0.3)
    fig.autofmt_xdate()

    add_watermark(fig, chart_config)
    fig.tight_layout()

    chart = fig_to_base64(fig, chart_config, width=1000, height=500)
    chart['title'] = 'Sales Trend'

    # Summary stats
    summary = {
        'totalRevenue': float(daily['total'].sum()),
        'totalRevenueFormatted': format_currency(daily['total'].sum(), chart_config),
        'avgDailyRevenue': float(daily['total'].mean()),
        'avgDailyRevenueFormatted': format_currency(daily['total'].mean(), chart_config),
        'peakDay': str(daily.loc[daily['total'].idxmax(), 'date'].date()),
        'peakDayRevenue': float(daily['total'].max()),
        'totalTransactions': int(daily['count'].sum()),
        'days': len(daily),
        'trend': 'up' if daily['ma'].iloc[-1] > daily['ma'].iloc[0] else 'down',
        'trendPct': float(((daily['ma'].iloc[-1] / daily['ma'].iloc[0]) - 1) * 100)
            if daily['ma'].iloc[0] > 0 else 0,
    }

    return {
        'summary': summary,
        'charts': [chart],
    }
`;

export const CHARTS_SCATTER_PY = `"""
Scatter / Bubble Chart — Margin vs Volume analysis.

Plots products on a scatter with X = quantity sold, Y = profit margin,
bubble size = total revenue. Helps identify high-volume low-margin products
vs low-volume high-margin ones.

Input data:
  [{ "product_name": "Widget A", "quantity": 50, "revenue": 5000,
     "cost": 3000, "margin": 40 }, ...]
"""

import pandas as pd
import numpy as np
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
from charts import apply_style, fig_to_base64, get_color_palette, add_watermark, format_currency


def run(data: list, params: dict, chart_config: dict) -> dict:
    if not data:
        return {"error": "No data provided"}

    colors = apply_style(chart_config)
    palette = get_color_palette(colors, 6)

    df = pd.DataFrame(data)

    # Resolve columns
    product_col = next((c for c in ['product_name', 'name', 'sku', 'item', 'product'] if c in df.columns), None)
    qty_col = next((c for c in ['quantity', 'qty', 'units_sold', 'volume'] if c in df.columns), None)
    revenue_col = next((c for c in ['revenue', 'amount', 'total', 'sales'] if c in df.columns), None)
    cost_col = next((c for c in ['cost', 'cogs', 'total_cost'] if c in df.columns), None)
    margin_col = next((c for c in ['margin', 'profit_margin', 'margin_pct', 'gross_margin'] if c in df.columns), None)
    category_col = next((c for c in ['category', 'department', 'group', 'type'] if c in df.columns), None)

    if not product_col:
        return {"error": "No product column found"}

    # Compute margin if not provided
    for col in [qty_col, revenue_col, cost_col]:
        if col:
            df[col] = pd.to_numeric(df[col], errors='coerce').fillna(0)

    if margin_col:
        df[margin_col] = pd.to_numeric(df[margin_col], errors='coerce').fillna(0)
    elif revenue_col and cost_col:
        margin_col = '_margin'
        df[margin_col] = ((df[revenue_col] - df[cost_col]) / df[revenue_col].replace(0, np.nan) * 100).fillna(0)
    else:
        return {"error": "Need either margin column, or revenue + cost columns to compute margin"}

    x_col = qty_col or revenue_col
    if not x_col:
        return {"error": "Need quantity or revenue column for X axis"}

    # Aggregate by product
    agg_cols = {x_col: 'sum', margin_col: 'mean'}
    if revenue_col and revenue_col != x_col:
        agg_cols[revenue_col] = 'sum'
    if category_col:
        agg_cols[category_col] = 'first'

    grouped = df.groupby(product_col).agg(agg_cols).reset_index()

    size_col = revenue_col if revenue_col else x_col
    sizes = grouped[size_col]
    # Normalize bubble sizes
    size_min, size_max = sizes.min(), sizes.max()
    if size_max > size_min:
        normalized_sizes = 50 + (sizes - size_min) / (size_max - size_min) * 500
    else:
        normalized_sizes = pd.Series([100] * len(sizes))

    # ── Chart ──
    fig, ax = plt.subplots(figsize=(12, 8))

    if category_col:
        categories = grouped[category_col].unique()
        cat_colors = {cat: palette[i % len(palette)] for i, cat in enumerate(categories)}
        for cat in categories:
            mask = grouped[category_col] == cat
            subset = grouped[mask]
            ax.scatter(
                subset[x_col], subset[margin_col],
                s=normalized_sizes[mask], c=cat_colors[cat],
                alpha=0.6, edgecolors='white', linewidth=0.5, label=str(cat)
            )
        ax.legend(fontsize=8, loc='best')
    else:
        ax.scatter(
            grouped[x_col], grouped[margin_col],
            s=normalized_sizes, c=palette[0],
            alpha=0.6, edgecolors='white', linewidth=0.5
        )

    # Label top products
    top_n = min(10, len(grouped))
    top_products = grouped.nlargest(top_n, size_col)
    for _, row in top_products.iterrows():
        ax.annotate(str(row[product_col]), (row[x_col], row[margin_col]),
                    fontsize=7, ha='center', va='bottom', alpha=0.8)

    # Quadrant lines at medians
    med_x = grouped[x_col].median()
    med_y = grouped[margin_col].median()
    ax.axvline(med_x, color='gray', linestyle='--', alpha=0.3)
    ax.axhline(med_y, color='gray', linestyle='--', alpha=0.3)

    # Quadrant labels
    ax.text(0.02, 0.98, 'Low Vol / High Margin', transform=ax.transAxes, fontsize=8,
            va='top', ha='left', alpha=0.5, style='italic')
    ax.text(0.98, 0.98, 'High Vol / High Margin ★', transform=ax.transAxes, fontsize=8,
            va='top', ha='right', alpha=0.5, style='italic')
    ax.text(0.02, 0.02, 'Low Vol / Low Margin ⚠', transform=ax.transAxes, fontsize=8,
            va='bottom', ha='left', alpha=0.5, style='italic')
    ax.text(0.98, 0.02, 'High Vol / Low Margin', transform=ax.transAxes, fontsize=8,
            va='bottom', ha='right', alpha=0.5, style='italic')

    ax.set_xlabel('Quantity Sold' if qty_col else 'Revenue')
    ax.set_ylabel('Profit Margin (%)')
    ax.set_title('Product Performance Matrix', fontsize=14, fontweight='bold')

    add_watermark(fig, chart_config)
    fig.tight_layout()
    chart = fig_to_base64(fig, chart_config, width=1200, height=800)
    chart['title'] = 'Margin vs Volume Scatter'

    # ── Summary ──
    summary = {
        'totalProducts': len(grouped),
        'avgMargin': round(float(grouped[margin_col].mean()), 1),
        'medianMargin': round(float(grouped[margin_col].median()), 1),
        'highVolHighMargin': int(((grouped[x_col] >= med_x) & (grouped[margin_col] >= med_y)).sum()),
        'highVolLowMargin': int(((grouped[x_col] >= med_x) & (grouped[margin_col] < med_y)).sum()),
        'lowVolHighMargin': int(((grouped[x_col] < med_x) & (grouped[margin_col] >= med_y)).sum()),
        'lowVolLowMargin': int(((grouped[x_col] < med_x) & (grouped[margin_col] < med_y)).sum()),
    }

    table = {
        'columns': ['Product', 'Quantity', 'Revenue', 'Margin %', 'Quadrant'],
        'rows': [],
    }
    for _, row in grouped.sort_values(margin_col, ascending=False).head(50).iterrows():
        vol = 'High' if row[x_col] >= med_x else 'Low'
        mgn = 'High' if row[margin_col] >= med_y else 'Low'
        table['rows'].append([
            str(row[product_col]),
            int(row[x_col]),
            format_currency(row[size_col], chart_config) if revenue_col else int(row[x_col]),
            f"{row[margin_col]:.1f}%",
            f"{vol} Vol / {mgn} Margin",
        ])

    return {
        'summary': summary,
        'charts': [chart],
        'table': table,
    }
`;

export const CHARTS_TREEMAP_PY = `"""
Treemap — Hierarchical revenue visualization using squarify.

Shows category/product revenue as nested rectangles proportional to value.
Supports two levels: category → product.

Input data:
  [{ "product_name": "Widget A", "category": "Electronics", "revenue": 5000 }, ...]
"""

import pandas as pd
import numpy as np
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
import squarify
from charts import apply_style, fig_to_base64, get_color_palette, add_watermark, format_currency


def run(data: list, params: dict, chart_config: dict) -> dict:
    if not data:
        return {"error": "No data provided"}

    colors = apply_style(chart_config)
    palette = get_color_palette(colors, 20)

    df = pd.DataFrame(data)

    # Resolve columns
    product_col = next((c for c in ['product_name', 'name', 'sku', 'item', 'product'] if c in df.columns), None)
    category_col = next((c for c in ['category', 'department', 'group', 'type'] if c in df.columns), None)
    value_col = next((c for c in ['revenue', 'amount', 'total', 'sales', 'quantity'] if c in df.columns), None)

    if not value_col:
        return {"error": "No revenue/amount column found"}

    df[value_col] = pd.to_numeric(df[value_col], errors='coerce').fillna(0)
    df = df[df[value_col] > 0]

    group_col = category_col or product_col
    if not group_col:
        return {"error": "No product or category column found"}

    # Aggregate by group
    grouped = df.groupby(group_col)[value_col].sum().sort_values(ascending=False)
    total = grouped.sum()

    # Limit to top N for readability
    max_items = params.get('maxItems', 30)
    if len(grouped) > max_items:
        top = grouped.head(max_items - 1)
        others = pd.Series({'Others': grouped.iloc[max_items - 1:].sum()})
        grouped = pd.concat([top, others])

    # ── Treemap chart ──
    fig, ax = plt.subplots(figsize=(14, 8))

    labels = []
    for name, val in grouped.items():
        pct = val / total * 100
        currency_val = format_currency(val, chart_config)
        labels.append(f"{name}\\n{currency_val}\\n({pct:.1f}%)")

    squarify.plot(
        sizes=grouped.values,
        label=labels,
        color=palette[:len(grouped)],
        alpha=0.8,
        ax=ax,
        text_kwargs={'fontsize': 8, 'fontweight': 'bold'},
        pad=2,
    )

    ax.set_title(
        f'Revenue by {"Category" if category_col else "Product"} (Total: {format_currency(total, chart_config)})',
        fontsize=14, fontweight='bold', pad=20
    )
    ax.axis('off')

    add_watermark(fig, chart_config)
    fig.tight_layout()
    chart = fig_to_base64(fig, chart_config, width=1400, height=800)
    chart['title'] = f'Revenue Treemap by {"Category" if category_col else "Product"}'

    # ── If both category and product, make a second detail chart ──
    charts = [chart]
    if category_col and product_col:
        # Show top 5 categories with their top products inside
        top_cats = df.groupby(category_col)[value_col].sum().nlargest(5).index
        fig2, axes2 = plt.subplots(1, min(5, len(top_cats)), figsize=(16, 5))
        if len(top_cats) == 1:
            axes2 = [axes2]

        for i, cat in enumerate(top_cats[:5]):
            cat_data = df[df[category_col] == cat].groupby(product_col)[value_col].sum().sort_values(ascending=False).head(10)
            cat_total = cat_data.sum()
            cat_labels = [f"{n}\\n{format_currency(v, chart_config)}" for n, v in cat_data.items()]
            squarify.plot(
                sizes=cat_data.values,
                label=cat_labels,
                color=palette[i * 4:(i * 4) + len(cat_data)],
                alpha=0.8,
                ax=axes2[i],
                text_kwargs={'fontsize': 7},
                pad=1,
            )
            axes2[i].set_title(f'{cat} ({format_currency(cat_total, chart_config)})', fontsize=10, fontweight='bold')
            axes2[i].axis('off')

        add_watermark(fig2, chart_config)
        fig2.tight_layout()
        chart2 = fig_to_base64(fig2, chart_config, width=1600, height=500)
        chart2['title'] = 'Category Detail Treemaps'
        charts.append(chart2)

    # ── Summary ──
    summary = {
        'totalRevenue': round(float(total), 2),
        'itemCount': len(grouped),
        'topItem': str(grouped.index[0]),
        'topItemRevenue': round(float(grouped.iloc[0]), 2),
        'topItemPct': round(float(grouped.iloc[0] / total * 100), 1),
        'top5Pct': round(float(grouped.head(5).sum() / total * 100), 1),
    }

    # ── Table ──
    table = {
        'columns': ['Rank', 'Category' if category_col else 'Product', 'Revenue', '% of Total', 'Cumulative %'],
        'rows': [],
    }
    cumulative = 0
    for rank, (name, val) in enumerate(grouped.items(), 1):
        pct = val / total * 100
        cumulative += pct
        table['rows'].append([
            rank, str(name), format_currency(val, chart_config),
            f"{pct:.1f}%", f"{cumulative:.1f}%",
        ])

    return {
        'summary': summary,
        'charts': charts,
        'table': table,
    }
`;

export const CHARTS_WATERFALL_PY = `"""
Waterfall Chart — Revenue contribution breakdown.

Shows how individual categories, products, or time periods contribute
to a total, with positive (green) and negative (red) bars.

Input data:
  [{ "label": "January", "value": 5000 }, ...]
  OR [{ "product_name": "Widget A", "revenue": 5000 }, ...]
"""

import pandas as pd
import numpy as np
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
from charts import apply_style, fig_to_base64, get_color_palette, add_watermark, format_currency


def run(data: list, params: dict, chart_config: dict) -> dict:
    if not data:
        return {"error": "No data provided"}

    colors = apply_style(chart_config)
    palette = get_color_palette(colors, 6)

    df = pd.DataFrame(data)

    # Resolve columns
    label_col = next((c for c in ['label', 'name', 'product_name', 'category', 'period', 'month'] if c in df.columns), None)
    value_col = next((c for c in ['value', 'revenue', 'amount', 'total', 'contribution', 'change'] if c in df.columns), None)

    if not label_col or not value_col:
        return {"error": f"Need label and value columns. Found: {list(df.columns)}"}

    df[value_col] = pd.to_numeric(df[value_col], errors='coerce').fillna(0)

    # Mode: contribution (individual values) vs cumulative (running total)
    mode = params.get('mode', 'contribution')

    labels = df[label_col].astype(str).tolist()
    values = df[value_col].tolist()

    # ── Build waterfall data ──
    # Each bar starts where the previous ended
    cumulative = 0
    starts = []
    bar_values = []
    bar_colors = []

    positive_color = palette[0]
    negative_color = palette[3] if len(palette) > 3 else '#ef4444'
    total_color = palette[1]

    for v in values:
        starts.append(cumulative)
        bar_values.append(v)
        bar_colors.append(positive_color if v >= 0 else negative_color)
        cumulative += v

    # Add total bar
    labels.append('Total')
    starts.append(0)
    bar_values.append(cumulative)
    bar_colors.append(total_color)

    # ── Chart ──
    fig, ax = plt.subplots(figsize=(max(10, len(labels) * 0.8), 6))

    x_pos = range(len(labels))

    # Draw bars
    bars = ax.bar(x_pos, bar_values, bottom=starts, color=bar_colors, alpha=0.85,
                  edgecolor='white', linewidth=0.5, width=0.6)

    # Draw connector lines between bars (except before Total)
    for i in range(len(values)):
        connector_y = starts[i] + values[i]
        if i < len(values) - 1:
            ax.plot([i + 0.3, i + 0.7], [connector_y, connector_y],
                    color='gray', linewidth=0.8, linestyle='-', alpha=0.5)

    # Value labels on bars
    for i, (start, val) in enumerate(zip(starts, bar_values)):
        y_pos = start + val / 2
        label_text = format_currency(abs(val), chart_config)
        if val < 0:
            label_text = f"-{label_text}"
        ax.text(i, start + val + (cumulative * 0.01 if val >= 0 else cumulative * -0.01),
                label_text, ha='center', va='bottom' if val >= 0 else 'top',
                fontsize=8, fontweight='bold')

    ax.set_xticks(x_pos)
    ax.set_xticklabels(labels, rotation=45, ha='right', fontsize=9)
    ax.set_ylabel('Value')
    ax.set_title('Revenue Waterfall', fontsize=14, fontweight='bold')
    ax.axhline(0, color='black', linewidth=0.5, alpha=0.3)

    add_watermark(fig, chart_config)
    fig.tight_layout()
    chart = fig_to_base64(fig, chart_config, width=max(1000, len(labels) * 80), height=600)
    chart['title'] = 'Revenue Waterfall Chart'

    # ── Summary ──
    positive_sum = sum(v for v in values if v > 0)
    negative_sum = sum(v for v in values if v < 0)
    summary = {
        'totalValue': round(float(cumulative), 2),
        'positiveContributions': round(float(positive_sum), 2),
        'negativeContributions': round(float(negative_sum), 2),
        'itemCount': len(values),
        'largestPositive': {
            'label': str(labels[values.index(max(values))]) if values else '',
            'value': round(float(max(values)), 2) if values else 0,
        },
        'largestNegative': {
            'label': str(labels[values.index(min(values))]) if values else '',
            'value': round(float(min(values)), 2) if values else 0,
        },
    }

    # ── Table ──
    table = {
        'columns': ['Item', 'Value', 'Running Total', '% of Total'],
        'rows': [],
    }
    running = 0
    for lbl, val in zip(df[label_col].astype(str).tolist(), values):
        running += val
        pct = (val / cumulative * 100) if cumulative != 0 else 0
        table['rows'].append([
            lbl, format_currency(val, chart_config),
            format_currency(running, chart_config), f"{pct:.1f}%",
        ])

    return {
        'summary': summary,
        'charts': [chart],
        'table': table,
    }
`;

export const CHARTS_INIT_PY = `"""
Chart Utilities — Shared helpers for all chart modules.

Handles brand-aware styling, currency formatting, base64 encoding,
and consistent chart output format.
"""

import io
import base64
import warnings
import logging
import matplotlib
matplotlib.use('Agg')  # Non-interactive backend for server-side rendering
# Suppress font-not-found warnings before any pyplot import.
# The snapshot uses system fonts (DejaVu Sans etc); 'Inter' won't be found
# and matplotlib emits noisy warnings that pollute stdout and confuse the
# JSON parser in the TypeScript layer.
warnings.filterwarnings('ignore', message='.*findfont.*')
logging.getLogger('matplotlib.font_manager').setLevel(logging.ERROR)
import matplotlib.pyplot as plt
import matplotlib.ticker as mticker


def apply_style(chart_config: dict) -> dict:
    """Apply brand-aware styling from chart_config. Returns resolved colors."""
    style = chart_config.get('chartStyle', 'modern')
    
    if style == 'minimal':
        plt.style.use('seaborn-v0_8-whitegrid')
    elif style == 'classic':
        plt.style.use('classic')
    else:  # modern (default)
        plt.style.use('seaborn-v0_8-darkgrid')
    
    colors = {
        'primary': chart_config.get('primaryColor', '#3b82f6'),
        'secondary': chart_config.get('secondaryColor', '#10b981'),
        'accent': chart_config.get('accentColor', '#f59e0b'),
        'background': chart_config.get('background', '#ffffff'),
        'text': '#1f2937',
        'grid': '#e5e7eb',
    }
    
    # Set matplotlib params
    plt.rcParams.update({
        'figure.facecolor': colors['background'],
        'axes.facecolor': colors['background'],
        'text.color': colors['text'],
        'axes.labelcolor': colors['text'],
        'xtick.color': colors['text'],
        'ytick.color': colors['text'],
    })
    
    # Font family — default to 'sans-serif' (always available in the snapshot).
    # If chart_config specifies a custom font like 'Inter' that isn't installed,
    # matplotlib falls back gracefully; the warning is already suppressed above.
    font = chart_config.get('fontFamily', 'sans-serif')
    try:
        plt.rcParams['font.family'] = font
    except Exception:
        plt.rcParams['font.family'] = 'sans-serif'
    
    return colors


def format_currency(value, chart_config: dict) -> str:
    """Format a number as currency using chart_config settings."""
    symbol = chart_config.get('currencySymbol', 'KES')
    position = chart_config.get('currencyPosition', 'prefix')
    
    if abs(value) >= 1_000_000:
        formatted = f"{value/1_000_000:,.1f}M"
    elif abs(value) >= 1_000:
        formatted = f"{value/1_000:,.1f}K"
    else:
        formatted = f"{value:,.0f}"
    
    if position == 'suffix':
        return f"{formatted} {symbol}"
    return f"{symbol} {formatted}"


def currency_formatter(chart_config: dict):
    """Return a matplotlib FuncFormatter for currency axis labels."""
    def _fmt(x, pos):
        return format_currency(x, chart_config)
    return mticker.FuncFormatter(_fmt)


def fig_to_base64(fig, chart_config: dict, width: int = 800, height: int = 400) -> dict:
    """Convert a matplotlib figure to a base64-encoded PNG dict."""
    dpi = chart_config.get('dpiWeb', 150)
    
    buf = io.BytesIO()
    fig.savefig(buf, format='png', dpi=dpi, bbox_inches='tight',
                facecolor=fig.get_facecolor(), edgecolor='none')
    buf.seek(0)
    b64 = base64.b64encode(buf.read()).decode('utf-8')
    buf.close()
    plt.close(fig)
    
    return {
        'format': 'png',
        'data': b64,
        'width': width,
        'height': height,
    }


def get_color_palette(colors: dict, n: int = 6) -> list:
    """Generate a color palette with n colors based on brand colors."""
    base = [colors['primary'], colors['secondary'], colors['accent']]
    
    # Extend with complementary colors if needed
    extras = ['#6366f1', '#ec4899', '#14b8a6', '#f97316', '#8b5cf6', '#06b6d4']
    palette = base + [c for c in extras if c not in base]
    
    return palette[:n]


def add_watermark(fig, chart_config: dict):
    """Add watermark text if enabled."""
    if chart_config.get('watermarkEnabled') and chart_config.get('watermarkText'):
        fig.text(0.5, 0.5, chart_config['watermarkText'],
                fontsize=40, color='gray', alpha=0.1,
                ha='center', va='center', rotation=30,
                transform=fig.transFigure)
`;

