export const FORECASTING_ARIMA_PY = `"""
ARIMA/SARIMA Forecast — For products with strong seasonal patterns.

Uses statsmodels auto_arima-like grid search for optimal (p,d,q)(P,D,Q,s).

Input data format:
  [{ "date": "2026-01-15", "quantity": 42 }, ...]

Params:
  autoOrder (bool, default True)
  maxP, maxD, maxQ (int)
  seasonal (bool, default True)
  seasonalPeriod (int, default 7)
  horizonDays (int, default 30)
"""

import pandas as pd
import numpy as np
import warnings
warnings.filterwarnings('ignore')

from statsmodels.tsa.statespace.sarimax import SARIMAX
from statsmodels.tsa.stattools import adfuller
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
from charts import apply_style, fig_to_base64, get_color_palette, add_watermark


def _auto_order(series, max_p=5, max_d=2, max_q=5, seasonal=True, period=7):
    """Simple AIC-based grid search for SARIMA order."""
    best_aic = np.inf
    best_order = (1, 1, 1)
    best_seasonal = (0, 0, 0, period)

    # Determine differencing order
    d = 0
    temp = series.copy()
    for i in range(max_d + 1):
        result = adfuller(temp.dropna(), autolag='AIC')
        if result[1] < 0.05:
            d = i
            break
        temp = temp.diff().dropna()
        d = i + 1
    d = min(d, max_d)

    # Reduced search space for speed
    p_range = range(0, min(max_p + 1, 4))
    q_range = range(0, min(max_q + 1, 4))

    for p in p_range:
        for q in q_range:
            try:
                order = (p, d, q)
                s_order = (1, 1, 0, period) if seasonal and period > 1 else (0, 0, 0, 0)
                model = SARIMAX(series, order=order, seasonal_order=s_order,
                                enforce_stationarity=False, enforce_invertibility=False)
                fit = model.fit(disp=False, maxiter=50)
                if fit.aic < best_aic:
                    best_aic = fit.aic
                    best_order = order
                    best_seasonal = s_order
            except Exception:
                continue

    return best_order, best_seasonal, best_aic


def run(data: list, params: dict, chart_config: dict) -> dict:
    if not data:
        return {"error": "No data provided for ARIMA forecast"}

    colors = apply_style(chart_config)
    palette = get_color_palette(colors, 6)

    df = pd.DataFrame(data)

    # Resolve columns
    date_col = next((c for c in ['date', 'sale_date', 'created_at', 'order_date'] if c in df.columns), None)
    value_col = next((c for c in ['quantity', 'total_amount', 'amount', 'revenue', 'total'] if c in df.columns), None)

    if not date_col:
        return {"error": "No date column found"}
    if not value_col:
        return {"error": "No value column found"}

    df[date_col] = pd.to_datetime(df[date_col])
    df[value_col] = pd.to_numeric(df[value_col], errors='coerce').fillna(0)

    daily = df.groupby(df[date_col].dt.date)[value_col].sum().reset_index()
    daily.columns = ['date', 'value']
    daily['date'] = pd.to_datetime(daily['date'])
    daily = daily.sort_values('date').set_index('date')
    daily = daily.asfreq('D', fill_value=0)

    series = daily['value']
    if len(series) < 14:
        return {"error": f"ARIMA requires at least 14 data points, got {len(series)}"}

    # Parameters
    horizon = params.get('horizonDays', 30)
    seasonal = params.get('seasonal', True)
    period = params.get('seasonalPeriod', 7)
    auto = params.get('autoOrder', True)

    if auto:
        order, s_order, aic = _auto_order(
            series,
            max_p=params.get('maxP', 5),
            max_d=params.get('maxD', 2),
            max_q=params.get('maxQ', 5),
            seasonal=seasonal,
            period=period,
        )
    else:
        order = (1, 1, 1)
        s_order = (1, 1, 0, period) if seasonal else (0, 0, 0, 0)
        aic = None

    # Fit model
    try:
        model = SARIMAX(series, order=order, seasonal_order=s_order,
                        enforce_stationarity=False, enforce_invertibility=False)
        fit = model.fit(disp=False, maxiter=200)
    except Exception as e:
        return {"error": f"ARIMA model fitting failed: {str(e)}"}

    # Forecast
    fc = fit.get_forecast(steps=horizon)
    forecast_mean = fc.predicted_mean
    ci = fc.conf_int(alpha=0.05)
    forecast_dates = pd.date_range(start=series.index[-1] + pd.Timedelta(days=1), periods=horizon, freq='D')

    # ── Chart ──
    fig, ax = plt.subplots(figsize=(10, 5))

    ax.plot(series.index, series.values, color=palette[0], linewidth=1.5,
            alpha=0.7, label='Actual')
    ax.plot(forecast_dates, forecast_mean.values, color=palette[1],
            linewidth=2, linestyle='--', label=f'SARIMA Forecast ({horizon}d)')
    ax.fill_between(forecast_dates,
                     ci.iloc[:, 0].values,
                     ci.iloc[:, 1].values,
                     color=palette[1], alpha=0.15, label='95% CI')

    ax.set_title(f'SARIMA{order}×{s_order} Forecast', fontsize=14, fontweight='bold', pad=15)
    ax.set_ylabel(value_col.replace('_', ' ').title(), fontsize=11)
    ax.legend(loc='upper left', framealpha=0.9)
    ax.grid(True, alpha=0.3)
    fig.autofmt_xdate()
    add_watermark(fig, chart_config)
    fig.tight_layout()

    chart = fig_to_base64(fig, chart_config, width=1000, height=500)
    chart['title'] = f'SARIMA Forecast'

    summary = {
        'model': 'SARIMA',
        'order': list(order),
        'seasonalOrder': list(s_order),
        'aic': round(float(fit.aic), 1) if hasattr(fit, 'aic') else aic,
        'horizonDays': horizon,
        'totalForecast': float(forecast_mean.sum()),
        'avgDailyForecast': float(forecast_mean.mean()),
        'historicalDays': len(series),
        'historicalAvgDaily': float(series.mean()),
        'trend': 'up' if forecast_mean.mean() > series.tail(7).mean() else 'down',
    }

    return {
        'summary': summary,
        'charts': [chart],
    }
`;

export const FORECASTING_HOLT_WINTERS_PY = `"""
Holt-Winters Exponential Smoothing — Fast, lightweight forecasts.

Best for high-velocity products with clear seasonal patterns.
Much faster than Prophet/ARIMA — suitable for bulk forecasting across many SKUs.

Input data format:
  [{ "date": "2026-01-15", "quantity": 42 }, ...]

Params:
  seasonalPeriods (int, default 7)
  trend ("add" | "mul", default "add")
  seasonal ("add" | "mul", default "add")
  dampedTrend (bool, default True)
  horizonDays (int, default 30)
"""

import pandas as pd
import numpy as np
import warnings
warnings.filterwarnings('ignore')

from statsmodels.tsa.holtwinters import ExponentialSmoothing
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
from charts import apply_style, fig_to_base64, get_color_palette, add_watermark


def run(data: list, params: dict, chart_config: dict) -> dict:
    if not data:
        return {"error": "No data provided for Holt-Winters forecast"}

    colors = apply_style(chart_config)
    palette = get_color_palette(colors, 6)

    df = pd.DataFrame(data)

    # Resolve columns
    date_col = next((c for c in ['date', 'sale_date', 'created_at', 'order_date'] if c in df.columns), None)
    value_col = next((c for c in ['quantity', 'total_amount', 'amount', 'revenue', 'total'] if c in df.columns), None)

    if not date_col:
        return {"error": "No date column found"}
    if not value_col:
        return {"error": "No value column found"}

    df[date_col] = pd.to_datetime(df[date_col])
    df[value_col] = pd.to_numeric(df[value_col], errors='coerce').fillna(0)

    daily = df.groupby(df[date_col].dt.date)[value_col].sum().reset_index()
    daily.columns = ['date', 'value']
    daily['date'] = pd.to_datetime(daily['date'])
    daily = daily.sort_values('date').set_index('date')
    daily = daily.asfreq('D', fill_value=0)

    series = daily['value']

    # Parameters
    horizon = params.get('horizonDays', 30)
    seasonal_periods = params.get('seasonalPeriods', 7)
    trend_type = params.get('trend', 'add')
    seasonal_type = params.get('seasonal', 'add')
    damped = params.get('dampedTrend', True)

    if len(series) < seasonal_periods * 2:
        # Not enough data for seasonal — fall back to simple exponential smoothing
        seasonal_type = None
        seasonal_periods = None

    # Multiplicative requires all positive values
    if seasonal_type == 'mul' and (series <= 0).any():
        seasonal_type = 'add'
    if trend_type == 'mul' and (series <= 0).any():
        trend_type = 'add'

    try:
        model = ExponentialSmoothing(
            series,
            trend=trend_type,
            seasonal=seasonal_type,
            seasonal_periods=seasonal_periods,
            damped_trend=damped,
        )
        fit = model.fit(optimized=True)
    except Exception as e:
        return {"error": f"Holt-Winters fitting failed: {str(e)}"}

    # Forecast
    forecast = fit.forecast(horizon)
    forecast_dates = pd.date_range(start=series.index[-1] + pd.Timedelta(days=1), periods=horizon, freq='D')

    # Simple confidence interval estimation (± 1.96 * residual std)
    residuals = fit.resid.dropna()
    residual_std = residuals.std() if len(residuals) > 0 else 0
    ci_lower = forecast - 1.96 * residual_std
    ci_upper = forecast + 1.96 * residual_std

    # ── Chart ──
    fig, ax = plt.subplots(figsize=(10, 5))

    ax.plot(series.index, series.values, color=palette[0], linewidth=1.5,
            alpha=0.7, label='Actual')
    ax.plot(forecast_dates, forecast.values, color=palette[2],
            linewidth=2, linestyle='--', label=f'Holt-Winters ({horizon}d)')
    ax.fill_between(forecast_dates, ci_lower.values, ci_upper.values,
                     color=palette[2], alpha=0.12, label='95% CI')

    label_parts = []
    if trend_type: label_parts.append(f"trend={trend_type}")
    if seasonal_type: label_parts.append(f"seasonal={seasonal_type}")
    if damped: label_parts.append("damped")
    config_str = ", ".join(label_parts)

    ax.set_title(f'Holt-Winters Forecast ({config_str})', fontsize=13, fontweight='bold', pad=15)
    ax.set_ylabel(value_col.replace('_', ' ').title(), fontsize=11)
    ax.legend(loc='upper left', framealpha=0.9)
    ax.grid(True, alpha=0.3)
    fig.autofmt_xdate()
    add_watermark(fig, chart_config)
    fig.tight_layout()

    chart = fig_to_base64(fig, chart_config, width=1000, height=500)
    chart['title'] = 'Holt-Winters Forecast'

    summary = {
        'model': 'Holt-Winters',
        'trend': trend_type,
        'seasonal': seasonal_type,
        'seasonalPeriods': seasonal_periods,
        'dampedTrend': damped,
        'horizonDays': horizon,
        'totalForecast': float(forecast.sum()),
        'avgDailyForecast': float(forecast.mean()),
        'historicalDays': len(series),
        'historicalAvgDaily': float(series.mean()),
        'aic': round(float(fit.aic), 1) if hasattr(fit, 'aic') else None,
        'trend_direction': 'up' if forecast.mean() > series.tail(7).mean() else 'down',
    }

    return {
        'summary': summary,
        'charts': [chart],
    }
`;

export const FORECASTING_PROPHET_FORECAST_PY = `"""
Prophet Forecast — Per-product demand prediction with holiday calendar.

Uses Facebook Prophet for additive/multiplicative seasonal decomposition.
Supports country-specific holidays (Kenyan by default).

Input data format:
  [{ "date": "2026-01-15", "quantity": 42, "product_name": "Widget A" }, ...]

Params:
  horizonDays (int, default 30)
  confidenceInterval (float, default 0.95)
  seasonalityMode ("additive" | "multiplicative")
  includeHolidays (bool)
  holidayCountry (str, ISO 3166-1, default "KE")
"""

import pandas as pd
import numpy as np
import json
import sys

# Prophet may not be installed — graceful fallback
try:
    from prophet import Prophet
    HAS_PROPHET = True
except ImportError:
    HAS_PROPHET = False

import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
from charts import apply_style, fig_to_base64, format_currency, get_color_palette, add_watermark


def run(data: list, params: dict, chart_config: dict) -> dict:
    if not HAS_PROPHET:
        return {"error": "Prophet is not installed in the sandbox. Install with: pip install prophet"}

    if not data:
        return {"error": "No data provided for Prophet forecast"}

    colors = apply_style(chart_config)
    palette = get_color_palette(colors, 6)

    df = pd.DataFrame(data)

    # Resolve date column
    date_col = None
    for col in ['date', 'sale_date', 'created_at', 'order_date']:
        if col in df.columns:
            date_col = col
            break
    if not date_col:
        return {"error": "No date column found. Expected: date, sale_date, created_at, or order_date"}

    # Resolve value column
    value_col = None
    for col in ['quantity', 'total_amount', 'amount', 'revenue', 'total', 'count']:
        if col in df.columns:
            value_col = col
            break
    if not value_col:
        return {"error": "No value column found. Expected: quantity, total_amount, amount, revenue, or count"}

    df[date_col] = pd.to_datetime(df[date_col])
    df[value_col] = pd.to_numeric(df[value_col], errors='coerce').fillna(0)

    # Aggregate by date
    daily = df.groupby(df[date_col].dt.date)[value_col].sum().reset_index()
    daily.columns = ['ds', 'y']
    daily['ds'] = pd.to_datetime(daily['ds'])
    daily = daily.sort_values('ds')

    # Prophet configuration
    horizon_days = params.get('horizonDays', 30)
    confidence = params.get('confidenceInterval', 0.95)
    seasonality_mode = params.get('seasonalityMode', 'multiplicative')
    include_holidays = params.get('includeHolidays', True)
    holiday_country = params.get('holidayCountry', 'KE')

    model = Prophet(
        interval_width=confidence,
        seasonality_mode=seasonality_mode,
        daily_seasonality=False,
        weekly_seasonality=params.get('weeklySeasonality', True),
        yearly_seasonality=params.get('yearlySeasonality', True),
        changepoint_prior_scale=params.get('changepointSensitivity', 0.05),
    )

    if include_holidays:
        try:
            model.add_country_holidays(country_name=holiday_country)
        except Exception:
            pass  # Country not supported — continue without holidays

    model.fit(daily)

    future = model.make_future_dataframe(periods=horizon_days)
    forecast = model.predict(future)

    # ── Chart: Actual vs Forecast with confidence intervals ──
    fig, ax = plt.subplots(figsize=(10, 5))

    # Historical actuals
    ax.plot(daily['ds'], daily['y'], color=palette[0], linewidth=1.5,
            alpha=0.7, label='Actual', marker='.', markersize=3)

    # Forecast line (including historical fit)
    forecast_future = forecast[forecast['ds'] > daily['ds'].max()]
    ax.plot(forecast_future['ds'], forecast_future['yhat'], color=palette[1],
            linewidth=2, label=f'Forecast ({horizon_days}d)', linestyle='--')

    # Confidence intervals
    ax.fill_between(forecast_future['ds'],
                     forecast_future['yhat_lower'],
                     forecast_future['yhat_upper'],
                     color=palette[1], alpha=0.15,
                     label=f'{int(confidence*100)}% CI')

    ax.set_title('Demand Forecast (Prophet)', fontsize=14, fontweight='bold', pad=15)
    ax.set_xlabel('')
    ax.set_ylabel(value_col.replace('_', ' ').title(), fontsize=11)
    ax.legend(loc='upper left', framealpha=0.9)
    ax.grid(True, alpha=0.3)
    fig.autofmt_xdate()
    add_watermark(fig, chart_config)
    fig.tight_layout()

    chart = fig_to_base64(fig, chart_config, width=1000, height=500)
    chart['title'] = 'Demand Forecast (Prophet)'

    # ── Summary statistics ──
    future_forecast = forecast[forecast['ds'] > daily['ds'].max()]
    total_forecast = float(future_forecast['yhat'].sum())
    avg_daily_forecast = float(future_forecast['yhat'].mean())
    peak_day = future_forecast.loc[future_forecast['yhat'].idxmax()]

    # Trend direction
    last_actual_avg = float(daily['y'].tail(7).mean()) if len(daily) >= 7 else float(daily['y'].mean())
    first_forecast_avg = float(future_forecast['yhat'].head(7).mean())
    trend_pct = ((first_forecast_avg / last_actual_avg) - 1) * 100 if last_actual_avg > 0 else 0

    summary = {
        'model': 'Prophet',
        'horizonDays': horizon_days,
        'confidenceInterval': confidence,
        'seasonalityMode': seasonality_mode,
        'totalForecast': total_forecast,
        'avgDailyForecast': avg_daily_forecast,
        'peakForecastDay': str(peak_day['ds'].date()),
        'peakForecastValue': float(peak_day['yhat']),
        'historicalDays': len(daily),
        'historicalAvgDaily': float(daily['y'].mean()),
        'trend': 'up' if trend_pct > 2 else ('down' if trend_pct < -2 else 'stable'),
        'trendPct': round(trend_pct, 1),
    }

    # ── Table: forecast by week ──
    future_forecast = future_forecast.copy()
    future_forecast['week'] = future_forecast['ds'].dt.isocalendar().week
    weekly = future_forecast.groupby('week').agg(
        avg_forecast=('yhat', 'mean'),
        lower=('yhat_lower', 'mean'),
        upper=('yhat_upper', 'mean'),
    ).reset_index()

    table = {
        'columns': ['Week', 'Avg Forecast', 'Lower Bound', 'Upper Bound'],
        'rows': [[int(r['week']), round(r['avg_forecast'], 1),
                   round(r['lower'], 1), round(r['upper'], 1)]
                  for _, r in weekly.iterrows()],
    }

    return {
        'summary': summary,
        'charts': [chart],
        'table': table,
    }
`;

export const FORECASTING_SAFETY_STOCK_PY = `"""
Safety Stock & EOQ Calculator — Dynamic safety stock and optimal order quantities.

Uses actual demand variability (standard deviation of daily demand) rather than
static reorder points. Incorporates lead time variability for robust calculations.

Input data format:
  [{ "product_name": "Widget A", "date": "2026-01-15", "quantity": 5,
     "lead_time_days": 7, "unit_cost": 150, "reorder_point": 10 }, ...]

Params:
  serviceLevel (float, default 0.95)
  leadTimeDays (int, default 7) — fallback if not in data
  holdingCostPct (float, default 0.25)
  orderingCost (float, default 50)
"""

import pandas as pd
import numpy as np
from scipy import stats
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
from charts import apply_style, fig_to_base64, format_currency, currency_formatter, get_color_palette, add_watermark


def run(data: list, params: dict, chart_config: dict) -> dict:
    if not data:
        return {"error": "No data provided for safety stock calculation"}

    colors = apply_style(chart_config)
    palette = get_color_palette(colors, 8)

    df = pd.DataFrame(data)

    # Resolve columns
    product_col = next((c for c in ['product_name', 'name', 'sku', 'item'] if c in df.columns), None)
    date_col = next((c for c in ['date', 'sale_date', 'created_at', 'order_date'] if c in df.columns), None)
    qty_col = next((c for c in ['quantity', 'qty', 'units_sold', 'demand'] if c in df.columns), None)

    if not product_col:
        return {"error": "No product name column found"}
    if not date_col:
        return {"error": "No date column found"}
    if not qty_col:
        return {"error": "No quantity column found"}

    df[date_col] = pd.to_datetime(df[date_col])
    df[qty_col] = pd.to_numeric(df[qty_col], errors='coerce').fillna(0)

    # Parameters
    service_level = params.get('serviceLevel', 0.95)
    default_lead_time = params.get('leadTimeDays', 7)
    holding_cost_pct = params.get('holdingCostPct', 0.25)
    ordering_cost = params.get('orderingCost', 50)
    z_score = stats.norm.ppf(service_level)

    results = []
    for product, group in df.groupby(product_col):
        # Daily demand aggregation
        daily = group.groupby(group[date_col].dt.date)[qty_col].sum()
        avg_daily_demand = daily.mean()
        std_daily_demand = daily.std() if len(daily) > 1 else 0

        # Lead time (from data or default)
        if 'lead_time_days' in group.columns:
            lead_time = group['lead_time_days'].mean()
            lead_time_std = group['lead_time_days'].std() if len(group) > 1 else 0
        else:
            lead_time = default_lead_time
            lead_time_std = 0

        # Safety Stock = z * sqrt(LT * σd² + d̄² * σLT²)
        safety_stock = z_score * np.sqrt(
            lead_time * std_daily_demand**2 + avg_daily_demand**2 * lead_time_std**2
        )

        # Reorder Point = d̄ * LT + SS
        reorder_point = avg_daily_demand * lead_time + safety_stock

        # EOQ = sqrt(2 * D * S / H)
        annual_demand = avg_daily_demand * 365
        unit_cost = group['unit_cost'].mean() if 'unit_cost' in group.columns else 100
        holding_cost = unit_cost * holding_cost_pct
        eoq = np.sqrt(2 * annual_demand * ordering_cost / holding_cost) if holding_cost > 0 else 0

        # Current reorder point from data (if available)
        current_rop = group['reorder_point'].iloc[0] if 'reorder_point' in group.columns else None

        results.append({
            'product': str(product),
            'avgDailyDemand': round(float(avg_daily_demand), 2),
            'demandStdDev': round(float(std_daily_demand), 2),
            'leadTimeDays': round(float(lead_time), 1),
            'safetyStock': round(float(safety_stock), 0),
            'reorderPoint': round(float(reorder_point), 0),
            'currentReorderPoint': int(current_rop) if current_rop is not None else None,
            'eoq': round(float(eoq), 0),
            'annualDemand': round(float(annual_demand), 0),
            'unitCost': round(float(unit_cost), 2),
            'annualHoldingCost': round(float(holding_cost * eoq / 2), 2) if eoq > 0 else 0,
            'annualOrderingCost': round(float(ordering_cost * annual_demand / eoq), 2) if eoq > 0 else 0,
            'dataDays': len(daily),
        })

    results_df = pd.DataFrame(results).sort_values('annualDemand', ascending=False)

    # ── Chart: Safety Stock vs Current Reorder Points ──
    fig, axes = plt.subplots(1, 2, figsize=(12, 5))

    # Left: Safety stock by product (top 15)
    top = results_df.head(15)
    y_pos = range(len(top))
    axes[0].barh(y_pos, top['safetyStock'], color=palette[0], alpha=0.8, label='Safety Stock')
    axes[0].barh(y_pos, top['reorderPoint'], color=palette[1], alpha=0.3, label='Reorder Point')
    axes[0].set_yticks(y_pos)
    axes[0].set_yticklabels(top['product'], fontsize=8)
    axes[0].set_xlabel('Units')
    axes[0].set_title('Safety Stock & Reorder Points', fontsize=12, fontweight='bold')
    axes[0].legend(fontsize=8)
    axes[0].invert_yaxis()

    # Right: EOQ by product (top 15)
    axes[1].barh(y_pos, top['eoq'], color=palette[2], alpha=0.8)
    axes[1].set_yticks(y_pos)
    axes[1].set_yticklabels(top['product'], fontsize=8)
    axes[1].set_xlabel('Units')
    axes[1].set_title('Economic Order Quantity (EOQ)', fontsize=12, fontweight='bold')
    axes[1].invert_yaxis()

    add_watermark(fig, chart_config)
    fig.tight_layout()

    chart = fig_to_base64(fig, chart_config, width=1200, height=500)
    chart['title'] = 'Safety Stock & EOQ Analysis'

    # ── Summary ──
    summary = {
        'productCount': len(results),
        'serviceLevel': service_level,
        'zScore': round(z_score, 2),
        'defaultLeadTimeDays': default_lead_time,
        'avgSafetyStock': round(float(results_df['safetyStock'].mean()), 1),
        'avgEoq': round(float(results_df['eoq'].mean()), 1),
        'avgReorderPoint': round(float(results_df['reorderPoint'].mean()), 1),
        'totalAnnualHoldingCost': round(float(results_df['annualHoldingCost'].sum()), 2),
        'totalAnnualOrderingCost': round(float(results_df['annualOrderingCost'].sum()), 2),
    }

    # ── Table ──
    table = {
        'columns': ['Product', 'Avg Daily Demand', 'Safety Stock', 'Reorder Point', 'EOQ',
                     'Current ROP', 'ROP Δ'],
        'rows': [],
    }
    for _, r in results_df.iterrows():
        delta = ''
        if r['currentReorderPoint'] is not None:
            diff = r['reorderPoint'] - r['currentReorderPoint']
            delta = f"+{int(diff)}" if diff > 0 else str(int(diff))
        table['rows'].append([
            r['product'], r['avgDailyDemand'], int(r['safetyStock']),
            int(r['reorderPoint']), int(r['eoq']),
            r['currentReorderPoint'] if r['currentReorderPoint'] is not None else 'N/A',
            delta if delta else 'N/A',
        ])

    return {
        'summary': summary,
        'charts': [chart],
        'table': table,
    }
`;

