export const CLASSIFICATION_ABC_XYZ_PY = `"""
ABC-XYZ Classification — Dual-axis inventory segmentation.

ABC = Revenue contribution (Pareto): A = top 80%, B = next 15%, C = bottom 5%
XYZ = Demand variability (CV of weekly demand): X = stable, Y = moderate, Z = erratic

The 9-cell matrix (AX, AY, AZ, BX, BY, BZ, CX, CY, CZ) drives inventory strategy:
  AX → high value, stable demand  → lean JIT, tight safety stock
  AZ → high value, erratic demand → buffer stock, close monitoring
  CZ → low value, erratic         → drop or simplify

Input data:
  [{ "product_name": "Widget A", "date": "2026-01-15", "quantity": 5, "amount": 250 }, ...]

Params from AbcParams + XyzParams:
  aThresholdPct, bThresholdPct, xCvThreshold, yCvThreshold, periodDays, revenueMetric
"""

import pandas as pd
import numpy as np
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
from charts import apply_style, fig_to_base64, get_color_palette, add_watermark, format_currency, currency_formatter


def run(data: list, params: dict, chart_config: dict) -> dict:
    if not data:
        return {"error": "No data provided"}

    colors = apply_style(chart_config)
    palette = get_color_palette(colors, 9)

    df = pd.DataFrame(data)

    # Resolve columns
    product_col = next((c for c in ['product_name', 'name', 'sku', 'item', 'product'] if c in df.columns), None)
    date_col = next((c for c in ['date', 'sale_date', 'created_at', 'order_date'] if c in df.columns), None)
    qty_col = next((c for c in ['quantity', 'qty', 'units_sold', 'demand'] if c in df.columns), None)
    amt_col = next((c for c in ['amount', 'revenue', 'total', 'total_amount', 'sales'] if c in df.columns), None)

    if not product_col or not date_col:
        return {"error": f"Missing required columns. Found: {list(df.columns)}"}

    df[date_col] = pd.to_datetime(df[date_col])
    if qty_col:
        df[qty_col] = pd.to_numeric(df[qty_col], errors='coerce').fillna(0)
    if amt_col:
        df[amt_col] = pd.to_numeric(df[amt_col], errors='coerce').fillna(0)

    # ── Parameters ──
    a_pct = params.get('aThresholdPct', 80)
    b_pct = params.get('bThresholdPct', 15)
    x_cv = params.get('xCvThreshold', 0.5)
    y_cv = params.get('yCvThreshold', 1.0)

    # ── ABC: Revenue contribution ──
    revenue_col = amt_col or qty_col
    if not revenue_col:
        return {"error": "Need either amount or quantity column for ABC analysis"}

    product_revenue = df.groupby(product_col)[revenue_col].sum().sort_values(ascending=False)
    total_revenue = product_revenue.sum()
    cumulative_pct = (product_revenue.cumsum() / total_revenue * 100) if total_revenue > 0 else product_revenue * 0

    abc_map = {}
    for product, cum_pct in cumulative_pct.items():
        if cum_pct <= a_pct:
            abc_map[product] = 'A'
        elif cum_pct <= a_pct + b_pct:
            abc_map[product] = 'B'
        else:
            abc_map[product] = 'C'

    # ── XYZ: Demand variability (CV of weekly demand) ──
    df['_week'] = df[date_col].dt.isocalendar().week.astype(int)
    df['_year'] = df[date_col].dt.year
    demand_col = qty_col or revenue_col

    weekly = df.groupby([product_col, '_year', '_week'])[demand_col].sum().reset_index()
    weekly_stats = weekly.groupby(product_col)[demand_col].agg(['mean', 'std']).fillna(0)
    weekly_stats['cv'] = weekly_stats['std'] / weekly_stats['mean'].replace(0, np.nan)
    weekly_stats['cv'] = weekly_stats['cv'].fillna(0)

    xyz_map = {}
    for product, row in weekly_stats.iterrows():
        if row['cv'] <= x_cv:
            xyz_map[product] = 'X'
        elif row['cv'] <= y_cv:
            xyz_map[product] = 'Y'
        else:
            xyz_map[product] = 'Z'

    # ── Build results DataFrame ──
    results = []
    for product in product_revenue.index:
        abc = abc_map.get(product, 'C')
        xyz = xyz_map.get(product, 'Z')
        cv = weekly_stats.loc[product, 'cv'] if product in weekly_stats.index else 0
        rev = product_revenue[product]
        results.append({
            'product': str(product),
            'revenue': round(float(rev), 2),
            'revenuePct': round(float(rev / total_revenue * 100), 1) if total_revenue > 0 else 0,
            'cumulativePct': round(float(cumulative_pct[product]), 1),
            'abc': abc,
            'cv': round(float(cv), 3),
            'xyz': xyz,
            'segment': f"{abc}{xyz}",
        })

    results_df = pd.DataFrame(results)

    # ── Matrix counts ──
    matrix = {}
    for seg in ['AX', 'AY', 'AZ', 'BX', 'BY', 'BZ', 'CX', 'CY', 'CZ']:
        count = len(results_df[results_df['segment'] == seg])
        rev = results_df[results_df['segment'] == seg]['revenue'].sum()
        matrix[seg] = {'count': count, 'revenue': round(float(rev), 2)}

    # ── Chart 1: ABC-XYZ scatter ──
    fig, axes = plt.subplots(1, 2, figsize=(14, 6))

    # Scatter: revenue vs CV, colored by ABC class
    abc_colors = {'A': palette[0], 'B': palette[2], 'C': palette[4]}
    for abc_class in ['A', 'B', 'C']:
        mask = results_df['abc'] == abc_class
        subset = results_df[mask]
        axes[0].scatter(
            subset['cv'], subset['revenue'],
            c=abc_colors[abc_class], label=f"Class {abc_class} ({len(subset)})",
            alpha=0.7, s=50, edgecolors='white', linewidth=0.5
        )

    # Draw XYZ boundaries
    axes[0].axvline(x=x_cv, color='gray', linestyle='--', alpha=0.5, label=f'X/Y boundary (CV={x_cv})')
    axes[0].axvline(x=y_cv, color='gray', linestyle=':', alpha=0.5, label=f'Y/Z boundary (CV={y_cv})')
    axes[0].set_xlabel('Demand Variability (CV)')
    axes[0].set_ylabel('Total Revenue')
    axes[0].set_title('ABC-XYZ Classification', fontsize=12, fontweight='bold')
    axes[0].legend(fontsize=8)

    # Chart 2: Matrix heatmap
    matrix_data = np.zeros((3, 3))
    labels = [['AX', 'AY', 'AZ'], ['BX', 'BY', 'BZ'], ['CX', 'CY', 'CZ']]
    for i, row in enumerate(labels):
        for j, seg in enumerate(row):
            matrix_data[i][j] = matrix[seg]['count']

    im = axes[1].imshow(matrix_data, cmap='YlOrRd', aspect='auto')
    axes[1].set_xticks([0, 1, 2])
    axes[1].set_xticklabels(['X (Stable)', 'Y (Variable)', 'Z (Erratic)'])
    axes[1].set_yticks([0, 1, 2])
    axes[1].set_yticklabels(['A (High)', 'B (Medium)', 'C (Low)'])
    axes[1].set_title('Segment Matrix (Product Count)', fontsize=12, fontweight='bold')

    # Annotate cells
    for i in range(3):
        for j in range(3):
            seg = labels[i][j]
            count = matrix[seg]['count']
            axes[1].text(j, i, f"{seg}\\n{count}", ha='center', va='center',
                        fontsize=10, fontweight='bold',
                        color='white' if matrix_data[i][j] > matrix_data.max() * 0.6 else 'black')

    fig.colorbar(im, ax=axes[1], fraction=0.046, pad=0.04)
    add_watermark(fig, chart_config)
    fig.tight_layout()

    chart = fig_to_base64(fig, chart_config, width=1400, height=600)
    chart['title'] = 'ABC-XYZ Classification Matrix'

    # ── Summary ──
    summary = {
        'totalProducts': len(results),
        'totalRevenue': round(float(total_revenue), 2),
        'aCount': len(results_df[results_df['abc'] == 'A']),
        'bCount': len(results_df[results_df['abc'] == 'B']),
        'cCount': len(results_df[results_df['abc'] == 'C']),
        'xCount': len(results_df[results_df['xyz'] == 'X']),
        'yCount': len(results_df[results_df['xyz'] == 'Y']),
        'zCount': len(results_df[results_df['xyz'] == 'Z']),
        'matrix': matrix,
        'thresholds': {
            'aThresholdPct': a_pct,
            'bThresholdPct': b_pct,
            'xCvThreshold': x_cv,
            'yCvThreshold': y_cv,
        },
    }

    # ── Table ──
    table = {
        'columns': ['Product', 'Revenue', 'Revenue %', 'Cumul %', 'ABC', 'CV', 'XYZ', 'Segment'],
        'rows': [[r['product'], format_currency(r['revenue'], chart_config),
                   f"{r['revenuePct']}%", f"{r['cumulativePct']}%",
                   r['abc'], r['cv'], r['xyz'], r['segment']]
                  for r in results[:50]],
    }

    return {
        'summary': summary,
        'charts': [chart],
        'table': table,
    }
`;

export const CLASSIFICATION_BUNDLES_PY = `"""
Product Bundle Detection — Association Rule Mining (Apriori / FP-Growth).

Uses mlxtend to discover which products customers frequently buy together.
Returns rules sorted by lift (how much more likely items are bought together
vs. independently).

Input data:
  [{ "order_id": "ORD-001", "product_name": "Widget A" }, ...]

Params from BundleParams:
  minSupport, minConfidence, minLift, maxItemsPerRule
"""

import pandas as pd
import numpy as np
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
from charts import apply_style, fig_to_base64, get_color_palette, add_watermark


def run(data: list, params: dict, chart_config: dict) -> dict:
    if not data:
        return {"error": "No data provided"}

    colors = apply_style(chart_config)
    palette = get_color_palette(colors, 8)

    df = pd.DataFrame(data)

    # Resolve columns
    order_col = next((c for c in ['order_id', 'transaction_id', 'invoice_id', 'basket_id', 'id'] if c in df.columns), None)
    product_col = next((c for c in ['product_name', 'name', 'sku', 'item', 'product'] if c in df.columns), None)

    if not order_col or not product_col:
        return {"error": f"Need order_id and product_name columns. Found: {list(df.columns)}"}

    # Parameters
    min_support = params.get('minSupport', 0.01)
    min_confidence = params.get('minConfidence', 0.3)
    min_lift = params.get('minLift', 1.5)
    max_items = params.get('maxItemsPerRule', 3)

    # ── Build one-hot encoded basket matrix ──
    baskets = df.groupby([order_col, product_col]).size().reset_index(name='count')
    basket_matrix = baskets.pivot_table(
        index=order_col, columns=product_col, values='count', fill_value=0
    )
    # Convert to boolean (presence/absence)
    basket_bool = (basket_matrix > 0)

    total_baskets = len(basket_bool)
    if total_baskets < 10:
        return {"error": f"Only {total_baskets} baskets found. Need at least 10 for association rules."}

    unique_products = len(basket_bool.columns)
    if unique_products < 2:
        return {"error": "Need at least 2 unique products for bundle detection."}

    # ── Run Apriori ──
    try:
        from mlxtend.frequent_patterns import apriori, association_rules
    except ImportError:
        return {"error": "mlxtend library not installed. Install with: pip install mlxtend"}

    # Use fpgrowth if available (faster), fallback to apriori
    try:
        from mlxtend.frequent_patterns import fpgrowth
        frequent = fpgrowth(basket_bool, min_support=min_support, use_colnames=True, max_len=max_items)
    except Exception:
        frequent = apriori(basket_bool, min_support=min_support, use_colnames=True, max_len=max_items)

    if len(frequent) == 0:
        return {
            "summary": {
                "totalBaskets": total_baskets,
                "uniqueProducts": unique_products,
                "frequentItemsets": 0,
                "rules": 0,
                "message": f"No frequent itemsets found at min_support={min_support}. Try lowering minSupport."
            },
            "charts": [],
            "table": {"columns": [], "rows": []},
        }

    # ── Generate association rules ──
    rules = association_rules(frequent, metric="lift", min_threshold=min_lift, num_items_base=1)
    rules = rules[rules['confidence'] >= min_confidence]
    rules = rules.sort_values('lift', ascending=False).reset_index(drop=True)

    if len(rules) == 0:
        return {
            "summary": {
                "totalBaskets": total_baskets,
                "uniqueProducts": unique_products,
                "frequentItemsets": len(frequent),
                "rules": 0,
                "message": f"No rules found at min_confidence={min_confidence}, min_lift={min_lift}. Try lowering thresholds."
            },
            "charts": [],
            "table": {"columns": [], "rows": []},
        }

    # Format frozensets to readable strings
    rules['antecedents_str'] = rules['antecedents'].apply(lambda x: ' + '.join(sorted(x)))
    rules['consequents_str'] = rules['consequents'].apply(lambda x: ' + '.join(sorted(x)))
    rules['rule'] = rules['antecedents_str'] + ' → ' + rules['consequents_str']

    # ── Charts ──
    fig, axes = plt.subplots(1, 2, figsize=(14, 6))

    # 1. Top rules by lift
    top_rules = rules.head(15)
    y_pos = range(len(top_rules))
    bars = axes[0].barh(y_pos, top_rules['lift'], color=palette[0], alpha=0.8)
    axes[0].set_yticks(y_pos)
    axes[0].set_yticklabels(top_rules['rule'], fontsize=7)
    axes[0].set_xlabel('Lift')
    axes[0].set_title('Top Association Rules by Lift', fontsize=12, fontweight='bold')
    axes[0].invert_yaxis()
    for i, (_, row) in enumerate(top_rules.iterrows()):
        axes[0].text(row['lift'] + 0.1, i, f"conf={row['confidence']:.0%}", va='center', fontsize=7)

    # 2. Support vs Confidence scatter (size = lift)
    scatter = axes[1].scatter(
        rules['support'], rules['confidence'],
        s=rules['lift'] * 30, c=rules['lift'], cmap='YlOrRd',
        alpha=0.6, edgecolors='white', linewidth=0.5
    )
    axes[1].set_xlabel('Support')
    axes[1].set_ylabel('Confidence')
    axes[1].set_title('Support vs Confidence (size = Lift)', fontsize=12, fontweight='bold')
    fig.colorbar(scatter, ax=axes[1], label='Lift')

    add_watermark(fig, chart_config)
    fig.tight_layout()
    chart = fig_to_base64(fig, chart_config, width=1400, height=600)
    chart['title'] = 'Product Bundle Associations'

    # ── Summary ──
    summary = {
        'totalBaskets': total_baskets,
        'uniqueProducts': unique_products,
        'frequentItemsets': len(frequent),
        'rulesFound': len(rules),
        'avgLift': round(float(rules['lift'].mean()), 2),
        'maxLift': round(float(rules['lift'].max()), 2),
        'avgConfidence': round(float(rules['confidence'].mean()), 3),
        'avgSupport': round(float(rules['support'].mean()), 4),
        'topBundle': {
            'rule': rules.iloc[0]['rule'],
            'lift': round(float(rules.iloc[0]['lift']), 2),
            'confidence': round(float(rules.iloc[0]['confidence']), 3),
            'support': round(float(rules.iloc[0]['support']), 4),
        } if len(rules) > 0 else None,
    }

    # ── Table ──
    table = {
        'columns': ['Antecedent (If bought)', 'Consequent (Also buy)', 'Support', 'Confidence', 'Lift'],
        'rows': [
            [row['antecedents_str'], row['consequents_str'],
             f"{row['support']:.3f}", f"{row['confidence']:.1%}",
             f"{row['lift']:.2f}"]
            for _, row in rules.head(50).iterrows()
        ],
    }

    return {
        'summary': summary,
        'charts': [chart],
        'table': table,
    }
`;

export const CLASSIFICATION_CLV_PY = `"""
Customer Lifetime Value (CLV) — BG/NBD + Gamma-Gamma probabilistic model.

Uses the \`lifetimes\` library for:
  - BG/NBD (Beta-Geometric / Negative Binomial Distribution) — predicts future transactions
  - Gamma-Gamma submodel — predicts average monetary value per transaction
  - Combined CLV = predicted_transactions × predicted_avg_value × profit_margin

Input data:
  [{ "customer_name": "Alice", "date": "2026-01-15", "amount": 500 }, ...]

Params from ClvParams:
  predictionMonths, discountRateMonthly, minimumTransactions, model
"""

import pandas as pd
import numpy as np
from datetime import timedelta
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
from charts import apply_style, fig_to_base64, get_color_palette, add_watermark, format_currency


def run(data: list, params: dict, chart_config: dict) -> dict:
    if not data:
        return {"error": "No data provided"}

    colors = apply_style(chart_config)
    palette = get_color_palette(colors, 6)

    df = pd.DataFrame(data)

    # Resolve columns
    customer_col = next((c for c in ['customer_name', 'customer', 'name', 'client', 'buyer'] if c in df.columns), None)
    date_col = next((c for c in ['date', 'sale_date', 'created_at', 'order_date'] if c in df.columns), None)
    amt_col = next((c for c in ['amount', 'revenue', 'total', 'total_amount'] if c in df.columns), None)

    if not customer_col or not date_col or not amt_col:
        return {"error": f"Need customer, date, and amount columns. Found: {list(df.columns)}"}

    df[date_col] = pd.to_datetime(df[date_col])
    df[amt_col] = pd.to_numeric(df[amt_col], errors='coerce').fillna(0)
    df = df[df[amt_col] > 0]  # CLV only on positive transactions

    # Parameters
    prediction_months = params.get('predictionMonths', 12)
    discount_rate = params.get('discountRateMonthly', 0.01)
    min_transactions = params.get('minimumTransactions', 2)
    prediction_days = prediction_months * 30

    # ── Build RFM summary for lifetimes ──
    now = df[date_col].max()
    observation_start = df[date_col].min()
    observation_period = (now - observation_start).days

    try:
        from lifetimes.utils import summary_data_from_transaction_data
    except ImportError:
        return {"error": "lifetimes library not installed. Install with: pip install lifetimes"}

    rfm = summary_data_from_transaction_data(
        df, customer_col, date_col,
        monetary_value_col=amt_col,
        observation_period_end=now,
    )

    # Filter to customers with enough transactions
    rfm = rfm[rfm['frequency'] >= min_transactions]
    if len(rfm) == 0:
        return {"error": f"No customers with >= {min_transactions} transactions"}

    # ── Fit BG/NBD model ──
    from lifetimes import BetaGeoFitter
    bgf = BetaGeoFitter(penalizer_coef=0.01)
    bgf.fit(rfm['frequency'], rfm['recency'], rfm['T'])

    # Predict future transactions
    rfm['predicted_purchases'] = bgf.conditional_expected_number_of_purchases_up_to_time(
        prediction_days, rfm['frequency'], rfm['recency'], rfm['T']
    )

    # ── Fit Gamma-Gamma model ──
    from lifetimes import GammaGammaFitter
    ggf = GammaGammaFitter(penalizer_coef=0.01)

    # Gamma-Gamma requires frequency > 0 and monetary_value > 0
    gg_data = rfm[(rfm['frequency'] > 0) & (rfm['monetary_value'] > 0)]
    ggf.fit(gg_data['frequency'], gg_data['monetary_value'])

    # Expected average profit per transaction
    rfm.loc[gg_data.index, 'predicted_avg_value'] = ggf.conditional_expected_average_profit(
        gg_data['frequency'], gg_data['monetary_value']
    )
    rfm['predicted_avg_value'] = rfm['predicted_avg_value'].fillna(rfm['monetary_value'])

    # ── CLV calculation ──
    rfm['clv'] = ggf.customer_lifetime_value(
        bgf, gg_data['frequency'], gg_data['recency'], gg_data['T'],
        gg_data['monetary_value'],
        time=prediction_months,
        discount_rate=discount_rate,
    ).reindex(rfm.index, fill_value=0)

    rfm = rfm.sort_values('clv', ascending=False).reset_index()

    # ── CLV segments ──
    rfm['clv_segment'] = pd.qcut(rfm['clv'], q=4, labels=['Low', 'Medium', 'High', 'Premium'], duplicates='drop')

    # ── Charts ──
    fig, axes = plt.subplots(1, 3, figsize=(16, 5))

    # 1. CLV distribution (histogram)
    axes[0].hist(rfm['clv'], bins=30, color=palette[0], alpha=0.8, edgecolor='white')
    axes[0].set_xlabel('Customer Lifetime Value')
    axes[0].set_ylabel('Customers')
    axes[0].set_title('CLV Distribution', fontsize=12, fontweight='bold')
    axes[0].axvline(rfm['clv'].median(), color=palette[1], linestyle='--', label=f"Median: {format_currency(rfm['clv'].median(), chart_config)}")
    axes[0].legend(fontsize=8)

    # 2. Top 20 customers by CLV
    top20 = rfm.head(20)
    y_pos = range(len(top20))
    axes[1].barh(y_pos, top20['clv'], color=palette[2], alpha=0.8)
    axes[1].set_yticks(y_pos)
    axes[1].set_yticklabels(top20[customer_col], fontsize=7)
    axes[1].set_xlabel('Predicted CLV')
    axes[1].set_title(f'Top 20 Customers ({prediction_months}mo CLV)', fontsize=12, fontweight='bold')
    axes[1].invert_yaxis()

    # 3. Segment revenue contribution
    seg_clv = rfm.groupby('clv_segment')['clv'].agg(['sum', 'count']).sort_values('sum', ascending=False)
    axes[2].bar(seg_clv.index.astype(str), seg_clv['sum'], color=palette[:len(seg_clv)])
    axes[2].set_xlabel('CLV Segment')
    axes[2].set_ylabel('Total Predicted CLV')
    axes[2].set_title('Predicted Revenue by Segment', fontsize=12, fontweight='bold')
    for i, (seg, row) in enumerate(seg_clv.iterrows()):
        axes[2].text(i, row['sum'], f"n={int(row['count'])}", ha='center', va='bottom', fontsize=8)

    add_watermark(fig, chart_config)
    fig.tight_layout()
    chart = fig_to_base64(fig, chart_config, width=1600, height=500)
    chart['title'] = f'Customer Lifetime Value ({prediction_months} Months)'

    # ── Summary ──
    summary = {
        'totalCustomers': len(rfm),
        'predictionMonths': prediction_months,
        'discountRateMonthly': discount_rate,
        'totalPredictedClv': round(float(rfm['clv'].sum()), 2),
        'avgClv': round(float(rfm['clv'].mean()), 2),
        'medianClv': round(float(rfm['clv'].median()), 2),
        'maxClv': round(float(rfm['clv'].max()), 2),
        'avgPredictedPurchases': round(float(rfm['predicted_purchases'].mean()), 2),
        'avgPredictedValue': round(float(rfm['predicted_avg_value'].mean()), 2),
        'segments': {
            str(seg): {
                'count': int(row['count']),
                'totalClv': round(float(row['sum']), 2),
            }
            for seg, row in seg_clv.iterrows()
        },
        'modelParams': {
            'bgNbd': {k: round(float(v), 4) for k, v in bgf.params_.items()},
            'gammaGamma': {k: round(float(v), 4) for k, v in ggf.params_.items()},
        },
    }

    # ── Table ──
    table = {
        'columns': ['Customer', 'Frequency', 'Recency (days)', 'Monetary Avg',
                     'Pred. Purchases', 'Pred. Avg Value', 'CLV', 'Segment'],
        'rows': [
            [str(row[customer_col]), int(row['frequency']), int(row['recency']),
             format_currency(row['monetary_value'], chart_config),
             round(float(row['predicted_purchases']), 1),
             format_currency(row['predicted_avg_value'], chart_config),
             format_currency(row['clv'], chart_config),
             str(row['clv_segment'])]
            for _, row in rfm.head(100).iterrows()
        ],
    }

    return {
        'summary': summary,
        'charts': [chart],
        'table': table,
    }
`;

export const CLASSIFICATION_RFM_PY = `"""
RFM Customer Segmentation — Recency / Frequency / Monetary scoring.

Assigns each customer a 3-digit score (e.g. 5-4-3) based on quantile bins,
then maps scores to named segments (Champions, Loyal, At Risk, Lost, etc.).

Input data:
  [{ "customer_name": "Alice", "date": "2026-01-15", "amount": 500,
     "order_id": "ORD-001" }, ...]

Params from RfmParams:
  recencyBins, frequencyBins, monetaryBins, analysisPeriodDays, segmentLabels
"""

import pandas as pd
import numpy as np
from datetime import datetime, timedelta
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
from charts import apply_style, fig_to_base64, get_color_palette, add_watermark, format_currency


def run(data: list, params: dict, chart_config: dict) -> dict:
    if not data:
        return {"error": "No data provided"}

    colors = apply_style(chart_config)
    palette = get_color_palette(colors, 8)

    df = pd.DataFrame(data)

    # Resolve columns
    customer_col = next((c for c in ['customer_name', 'customer', 'name', 'client', 'buyer'] if c in df.columns), None)
    date_col = next((c for c in ['date', 'sale_date', 'created_at', 'order_date'] if c in df.columns), None)
    amt_col = next((c for c in ['amount', 'revenue', 'total', 'total_amount'] if c in df.columns), None)
    order_col = next((c for c in ['order_id', 'id', 'transaction_id', 'invoice_id'] if c in df.columns), None)

    if not customer_col:
        return {"error": "No customer column found"}
    if not date_col:
        return {"error": "No date column found"}

    df[date_col] = pd.to_datetime(df[date_col])
    if amt_col:
        df[amt_col] = pd.to_numeric(df[amt_col], errors='coerce').fillna(0)

    # Parameters
    r_bins = params.get('recencyBins', 5)
    f_bins = params.get('frequencyBins', 5)
    m_bins = params.get('monetaryBins', 5)
    period_days = params.get('analysisPeriodDays', 365)

    # Filter to analysis period
    now = df[date_col].max()
    cutoff = now - timedelta(days=period_days)
    df = df[df[date_col] >= cutoff]

    if len(df) == 0:
        return {"error": "No data within analysis period"}

    # ── Compute RFM metrics per customer ──
    agg_dict = {}
    agg_dict['recency'] = (date_col, lambda x: (now - x.max()).days)

    if order_col:
        agg_dict['frequency'] = (order_col, 'nunique')
    else:
        agg_dict['frequency'] = (date_col, 'count')

    if amt_col:
        agg_dict['monetary'] = (amt_col, 'sum')

    rfm = df.groupby(customer_col).agg(**agg_dict).reset_index()

    if 'monetary' not in rfm.columns:
        rfm['monetary'] = rfm['frequency']

    # ── Score using quantile bins ──
    # Recency: lower is better → reverse scoring
    rfm['R'] = pd.qcut(rfm['recency'], q=r_bins, labels=range(r_bins, 0, -1), duplicates='drop').astype(int)
    rfm['F'] = pd.qcut(rfm['frequency'].rank(method='first'), q=f_bins, labels=range(1, f_bins + 1), duplicates='drop').astype(int)
    rfm['M'] = pd.qcut(rfm['monetary'].rank(method='first'), q=m_bins, labels=range(1, m_bins + 1), duplicates='drop').astype(int)

    rfm['rfm_score'] = rfm['R'] * 100 + rfm['F'] * 10 + rfm['M']

    # ── Segment assignment ──
    segment_labels = params.get('segmentLabels', {
        'champions': [5, 4, 4],
        'loyal': [3, 3, 3],
        'potential_loyalists': [4, 2, 2],
        'at_risk': [2, 3, 3],
        'hibernating': [1, 1, 1],
        'lost': [1, 1, 2],
    })

    def assign_segment(row):
        r, f, m = row['R'], row['F'], row['M']
        best_match = 'other'
        best_score = -1
        for label, thresholds in segment_labels.items():
            min_r, min_f, min_m = thresholds
            if r >= min_r and f >= min_f and m >= min_m:
                match_score = min_r + min_f + min_m
                if match_score > best_score:
                    best_score = match_score
                    best_match = label
        return best_match.replace('_', ' ').title()

    rfm['segment'] = rfm.apply(assign_segment, axis=1)

    # ── Segment summary ──
    seg_summary = rfm.groupby('segment').agg(
        count=(customer_col, 'count'),
        avg_recency=('recency', 'mean'),
        avg_frequency=('frequency', 'mean'),
        avg_monetary=('monetary', 'mean'),
        total_monetary=('monetary', 'sum'),
    ).reset_index()

    # ── Charts ──
    fig, axes = plt.subplots(1, 3, figsize=(16, 5))

    # 1. Segment distribution (pie)
    seg_counts = rfm['segment'].value_counts()
    axes[0].pie(seg_counts.values, labels=seg_counts.index, autopct='%1.0f%%',
                colors=palette[:len(seg_counts)], startangle=90, textprops={'fontsize': 8})
    axes[0].set_title('Customer Segments', fontsize=12, fontweight='bold')

    # 2. R vs F scatter colored by M
    scatter = axes[1].scatter(rfm['R'], rfm['F'], c=rfm['M'], cmap='RdYlGn',
                              alpha=0.6, s=30, edgecolors='white', linewidth=0.3)
    axes[1].set_xlabel('Recency Score')
    axes[1].set_ylabel('Frequency Score')
    axes[1].set_title('R vs F (color = Monetary)', fontsize=12, fontweight='bold')
    fig.colorbar(scatter, ax=axes[1], label='M Score')

    # 3. Revenue by segment (bar)
    seg_rev = seg_summary.sort_values('total_monetary', ascending=True)
    axes[2].barh(seg_rev['segment'], seg_rev['total_monetary'], color=palette[:len(seg_rev)])
    axes[2].set_xlabel('Total Revenue')
    axes[2].set_title('Revenue by Segment', fontsize=12, fontweight='bold')
    for i, (_, row) in enumerate(seg_rev.iterrows()):
        axes[2].text(row['total_monetary'] * 1.02, i, format_currency(row['total_monetary'], chart_config),
                    va='center', fontsize=8)

    add_watermark(fig, chart_config)
    fig.tight_layout()
    chart = fig_to_base64(fig, chart_config, width=1600, height=500)
    chart['title'] = 'RFM Customer Segmentation'

    # ── Summary ──
    summary = {
        'totalCustomers': len(rfm),
        'analysisPeriodDays': period_days,
        'segments': {
            row['segment']: {
                'count': int(row['count']),
                'avgRecencyDays': round(float(row['avg_recency']), 1),
                'avgFrequency': round(float(row['avg_frequency']), 1),
                'avgMonetary': round(float(row['avg_monetary']), 2),
                'totalRevenue': round(float(row['total_monetary']), 2),
            }
            for _, row in seg_summary.iterrows()
        },
        'avgRecencyDays': round(float(rfm['recency'].mean()), 1),
        'avgFrequency': round(float(rfm['frequency'].mean()), 1),
        'avgMonetary': round(float(rfm['monetary'].mean()), 2),
    }

    # ── Table ──
    rfm_sorted = rfm.sort_values('monetary', ascending=False)
    table = {
        'columns': ['Customer', 'Recency (days)', 'Frequency', 'Monetary', 'R', 'F', 'M', 'Segment'],
        'rows': [
            [str(row[customer_col]), int(row['recency']), int(row['frequency']),
             format_currency(row['monetary'], chart_config),
             int(row['R']), int(row['F']), int(row['M']), row['segment']]
            for _, row in rfm_sorted.head(100).iterrows()
        ],
    }

    return {
        'summary': summary,
        'charts': [chart],
        'table': table,
    }
`;

